// model_rwkv7.rs — RWKV-7 (WKV-7 time-mixing + channel-mixing) inference pipeline.
//
// Reference: RWKV/RWKV7-Goose-World3-2.9B-HF
// Architecture: linear-time RNN with dynamic time decay (w), dynamic attention (a),
//   value versioning (v_first), key adjustment (k_k / k_a), r_k bonus, two-stage gate.
//
// Ported from aether/src/kernels/wkv7.ts (timeMix7) + wkv6.ts (channelMixJS).

use crate::loader::{KnotConfig, OwnedBytes, WeightBackend};
use crate::math::{dequantize_q8_0_row, f16_to_f32};
use crate::model::{dequantize_f16_row, resolve_qtype, QType};
use std::sync::Arc;

// ─────────────────────────────────────────────────────────────────────────────
// Config
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct RWKV7Config {
    pub hidden_dim: usize,
    pub num_layers: usize,
    pub vocab_size: usize,
    pub n_heads: usize,
    pub head_size: usize, // hidden_dim / n_heads
    pub low_rank_w: usize,
    pub low_rank_a: usize,
    pub low_rank_v: usize,
    pub gate_inner: usize,
    pub ffn_inner: usize, // channel-mix key expansion (typically 4 * hidden_dim)
}

/// RWKV-7 "Goose" World uses a FIXED per-head dimension of 64 across the whole
/// family (0.1B … 2.9B); `num_heads = hidden_size / 64`. See `fla/layers/rwkv7.py`
/// (`self.head_dim = head_dim; self.num_heads = int(hidden_size // head_dim)`) and
/// `RWKV7Config.head_dim == 64`. The group-norm then uses `num_groups = num_heads`
/// with `eps = head_dim * norm_eps = 64 * 1e-5 = 64e-5`.
const RWKV7_HEAD_DIM: usize = 64;

impl RWKV7Config {
    pub fn from_knot(k: &KnotConfig) -> Self {
        let hidden = k.hidden_dim;

        // Head partition. The `encode-ssm-models.py` conversion defaulted
        // `num_attention_heads` to 32 (the RWKV-7 HF config carries
        // `num_heads: null` and only `head_dim: 64`), so the knot's
        // `rwkv_n_heads` / `head_dim` block reads 32 / 80 — WRONG. The real
        // architecture is head_dim = 64, num_heads = hidden / 64 (e.g. 2560/64
        // = 40 heads, not 32 × 80). A mis-partitioned head breaks every
        // per-head op (kk-normalize, the WKV outer products, group-norm groups,
        // the r_k bonus) by mixing channels across head boundaries — the model
        // then predicts a generic token (',') instead of " Paris".
        //
        // Prefer the RWKV-7 invariant head_dim = 64 whenever it divides hidden
        // (true for the whole Goose World family). Fall back to the config's
        // declared partition only when 64 does not divide hidden (e.g. the tiny
        // synthetic test harness with hidden = 32).
        let (n_heads, head_size) = if hidden.is_multiple_of(RWKV7_HEAD_DIM) {
            (hidden / RWKV7_HEAD_DIM, RWKV7_HEAD_DIM)
        } else {
            let nh = k.rwkv_n_heads.unwrap_or_else(|| k.num_heads.max(1)).max(1);
            (nh, hidden / nh)
        };
        let low_rank = k.rwkv_low_rank_w.unwrap_or((hidden / 32).max(1));
        Self {
            hidden_dim: hidden,
            num_layers: k.num_layers,
            vocab_size: k.vocab_size,
            n_heads,
            head_size,
            low_rank_w: low_rank,
            low_rank_a: k.rwkv_low_rank_a.unwrap_or(low_rank),
            low_rank_v: k.rwkv_low_rank_v.unwrap_or(low_rank),
            gate_inner: k.rwkv_gate_inner.unwrap_or(n_heads * 4),
            ffn_inner: k.intermediate_size,
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-layer recurrent state
// ─────────────────────────────────────────────────────────────────────────────

pub struct RWKV7LayerState {
    /// WKV state: [n_heads * head_size * head_size]
    pub wkv: Vec<f32>,
    /// Previous-token embedding for token shift: [hidden_dim]
    pub shift_x: Vec<f32>,
    /// Channel-mix previous state: [hidden_dim]
    pub channel_state: Vec<f32>,
    /// v_first: first-layer value output shared across all layers: [hidden_dim] or empty
    pub v_first: Vec<f32>,
}

impl RWKV7LayerState {
    pub fn new(hidden_dim: usize, n_heads: usize, head_size: usize) -> Self {
        Self {
            wkv: vec![0.0; n_heads * head_size * head_size],
            shift_x: vec![0.0; hidden_dim],
            channel_state: vec![0.0; hidden_dim],
            v_first: vec![],
        }
    }
    pub fn reset(&mut self) {
        self.wkv.fill(0.0);
        self.shift_x.fill(0.0);
        self.channel_state.fill(0.0);
        self.v_first.clear();
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Weight helpers (reuse the same pattern as model_mamba)
// ─────────────────────────────────────────────────────────────────────────────

fn fetch_f32(backend: &dyn WeightBackend, name: &str) -> Vec<f32> {
    let raw = backend
        .fetch_tensor(name)
        .unwrap_or_else(|_| panic!("RWKV7: missing tensor {name}"));
    let mut out = vec![0.0f32; raw.len() / 4];
    for (i, chunk) in raw.chunks_exact(4).enumerate() {
        out[i] = f32::from_le_bytes(chunk.try_into().unwrap());
    }
    out
}

fn fetch_or_zeros(backend: &dyn WeightBackend, name: &str, n: usize) -> Vec<f32> {
    if backend.has_tensor(name) {
        // qtype-aware: small vectors (norms / mix ratios / decay biases) are
        // usually F32 in the knot, but route through `fetch_auto` so a Q8_0 /
        // F16-stored vector still decodes correctly.
        fetch_auto(backend, name, n)
    } else {
        vec![0.0; n]
    }
}

fn fetch_f16(backend: &dyn WeightBackend, name: &str, n_elems: usize) -> Vec<f32> {
    let raw = backend.fetch_tensor(name).expect(name);
    let mut out = vec![0.0f32; n_elems];
    for (i, chunk) in raw.chunks_exact(2).enumerate() {
        if i >= n_elems {
            break;
        }
        out[i] = f16_to_f32(u16::from_le_bytes([chunk[0], chunk[1]]));
    }
    out
}

fn fetch_q8(backend: &dyn WeightBackend, name: &str, n_elems: usize) -> Vec<f32> {
    let raw = backend.fetch_tensor(name).expect(name);
    // GGUF Q8_0: 34-byte blocks = 2-byte LE fp16 scale d + 32 int8; x = d * q.
    const BLOCK: usize = 32;
    let mut out = vec![0.0f32; n_elems];
    let mut idx = 0usize;
    for chunk in raw.chunks_exact(2 + BLOCK) {
        let d = f16_to_f32(u16::from_le_bytes([chunk[0], chunk[1]]));
        for (j, &b) in chunk[2..].iter().enumerate() {
            if idx + j >= n_elems {
                break;
            }
            out[idx + j] = (b as i8) as f32 * d;
        }
        idx += BLOCK;
        if idx >= n_elems {
            break;
        }
    }
    out
}

fn fetch_auto(backend: &dyn WeightBackend, name: &str, n_elems: usize) -> Vec<f32> {
    if !backend.has_tensor(name) {
        return vec![0.0; n_elems];
    }
    let ttype = backend
        .tensor_info(name)
        .map(|i| i.tensor_type)
        .unwrap_or_default();
    match ttype.as_str() {
        "Q8_0" => fetch_q8(backend, name, n_elems),
        "F16" | "f16" | "fp16" | "FP16" | "half" => fetch_f16(backend, name, n_elems),
        _ => fetch_f32(backend, name),
    }
}

/// Number of f32 elements a tensor decodes to, from its byte length + qtype.
/// Q8_0 packs 32 i8 + a 2-byte fp16 scale per 34-byte block; F32 is 4 B/elem.
/// Returns None when the tensor is absent so callers can fall back to a default.
fn tensor_n_elems(backend: &dyn WeightBackend, name: &str) -> Option<usize> {
    let info = backend.tensor_info(name)?;
    let bytes = info.length as usize;
    Some(match info.tensor_type.as_str() {
        "Q8_0" => bytes / 34 * 32,
        "F16" | "f16" | "fp16" => bytes / 2,
        _ => bytes / 4, // F32 / default
    })
}

// ─────────────────────────────────────────────────────────────────────────────
// Math kernels
// ─────────────────────────────────────────────────────────────────────────────

#[inline(always)]
fn sigmoid(x: f32) -> f32 {
    1.0 / (1.0 + (-x).exp())
}

// ─────────────────────────────────────────────────────────────────────────────
// Q8/F16-RESIDENT weight matrix (mirrors the STT int8-resident win)
// ─────────────────────────────────────────────────────────────────────────────
//
// The old `from_knot` bulk-dequantized EVERY Q8_0 weight to a fully-resident
// `Vec<f32>` (≈ 10.8 GB for rwkv7-2.9b — over the wasm32 4 GB cap). Instead we
// keep the SOURCE-quant bytes resident (Q8_0 = i8 + per-32-block f16 scale, F16
// = 2 B/elem, or raw F32) and dequantize one weight ROW at a time, on the fly,
// inside the matvec — exactly the pattern that fixed STT (`mat_vec_q8`). Q8-
// resident 2.9B ≈ 2.9 GB, which fits wasm32's 4 GB in Node.
//
// Each row is dequantized into a small reused scratch buffer (baking in the
// per-row/per-block scale) using the transformer's OWN dequant kernels
// (`math::dequantize_q8_0_row` / `model::dequantize_f16_row`), then fed to the
// SAME `math::dot_product` the f32 path uses — so every `out[i]` is bit-
// identical to dequantizing the whole matrix up front and calling a row-wise
// f32 matmul. Memory cost is one `cols`-float scratch row, not the full matrix.
struct ResidentMat {
    /// Source-quant bytes, kept resident (Arc-shared with the host backend).
    bytes: OwnedBytes,
    qtype: QType,
    /// Output dimension (number of rows = `out.len()`).
    rows: usize,
    /// Input dimension (number of columns = `x.len()`).
    cols: usize,
}

impl ResidentMat {
    /// Fetch a tensor and keep it RESIDENT in its source quant (no bulk
    /// dequant). `rows`/`cols` come from the architecture config (same values
    /// the old `mat_vec` calls passed). The qtype is read from the backend's
    /// tensor metadata; absent metadata (e.g. the synthetic test backend)
    /// defaults to F32.
    fn from_backend(backend: &dyn WeightBackend, name: &str, rows: usize, cols: usize) -> Self {
        let bytes = backend
            .fetch_tensor(name)
            .unwrap_or_else(|e| panic!("RWKV7: fetch {name}: {e}"));
        let qtype = backend
            .tensor_info(name)
            .map(|i| resolve_qtype(&i.tensor_type))
            .unwrap_or(QType::F32);
        Self {
            bytes,
            qtype,
            rows,
            cols,
        }
    }

    /// Build from already-fetched bytes + explicit dims/qtype (no backend lookup).
    /// Used for the streaming path's transient single-row embed and lm_head shards,
    /// where the host pages the bytes and the qtype comes from the cached metadata.
    fn from_parts(bytes: OwnedBytes, qtype: QType, rows: usize, cols: usize) -> Self {
        Self {
            bytes,
            qtype,
            rows,
            cols,
        }
    }

    /// Dequantize row `row` (length `cols`) into `out`, using the transformer's
    /// existing per-row dequant kernels.
    #[inline]
    fn dequant_row_into(&self, row: usize, out: &mut [f32]) {
        let b: &[u8] = self.bytes.as_ref();
        match self.qtype {
            QType::Q8_0 => dequantize_q8_0_row(out, b, row, self.cols),
            QType::F16 => dequantize_f16_row(out, b, row, self.cols),
            QType::F32 => {
                let base = row * self.cols * 4;
                for (j, slot) in out.iter_mut().enumerate().take(self.cols) {
                    let o = base + j * 4;
                    *slot = f32::from_le_bytes([b[o], b[o + 1], b[o + 2], b[o + 3]]);
                }
            }
            other => panic!("RWKV7 resident matvec: unsupported qtype {other:?}"),
        }
    }
}

/// Sequential f32 dot — the NATIVE path. DELIBERATELY scalar / left-to-right
/// (not the arch-specific SIMD `math::dot_product`): on native, RWKV-7's headline
/// is that the wasm forward is BIT-IDENTICAL to the native forward, and a SIMD
/// reduction reassociates differently on aarch64 (NEON) vs wasm32 (simd128). This
/// scalar order exactly reproduces the previous dense-f32 `mat_vec` numerics, so
/// the native reference and the native `*_equals_resident` parity tests stay valid
/// without regeneration. The wasm32 build below uses a 4-lane simd128 reduction
/// instead (the fleet is compute-bound on this dot); it is numerically SOUND but
/// not bit-identical — coherence is re-verified by argmax on the live fleet.
#[cfg(not(target_arch = "wasm32"))]
#[inline]
fn seq_dot(a: &[f32], b: &[f32]) -> f32 {
    let mut s = 0.0f32;
    for j in 0..a.len() {
        s += a[j] * b[j];
    }
    s
}

/// WASM hot path: dispatch to a simd128 dot enabled PER-FUNCTION (not crate-wide,
/// which activated other slow/behavior-changing simd paths). `simd128` is a
/// baseline feature on the Cloudflare Workers V8 runtime, so the statically-enabled
/// intrinsics always validate at instantiation.
#[cfg(target_arch = "wasm32")]
#[inline]
fn seq_dot(a: &[f32], b: &[f32]) -> f32 {
    // SAFETY: the CF Workers wasm runtime supports simd128; the fn only reads
    // a[..n] and b[..n] (n = a.len()), the same bounds the scalar path required.
    unsafe { seq_dot_simd128(a, b) }
}

/// simd128 f32x4 dot — 4-lane fused-multiply-accumulate over the dequantized
/// weight row × the hidden state, scalar tail for the remainder. The reduction
/// reassociates vs the scalar path (lanes summed independently then horizontally),
/// so it is NOT bit-identical to native — sound but reordered; coherence is
/// re-verified by argmax on the live fleet. Mirrors aether's
/// `simd-kernel-matvec-q8_0.c` horizontal-sum pattern.
#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn seq_dot_simd128(a: &[f32], b: &[f32]) -> f32 {
    use core::arch::wasm32::*;
    let n = a.len();
    let mut acc = f32x4_splat(0.0);
    let mut j = 0usize;
    while j + 4 <= n {
        // v128.load permits any alignment on wasm (the align immediate is a hint);
        // f32 slices are 4-byte aligned, which is fine.
        let va = v128_load(a.as_ptr().add(j) as *const v128);
        let vb = v128_load(b.as_ptr().add(j) as *const v128);
        acc = f32x4_add(acc, f32x4_mul(va, vb));
        j += 4;
    }
    let mut s = f32x4_extract_lane::<0>(acc)
        + f32x4_extract_lane::<1>(acc)
        + f32x4_extract_lane::<2>(acc)
        + f32x4_extract_lane::<3>(acc);
    while j < n {
        s += a[j] * b[j];
        j += 1;
    }
    s
}

/// `out = W x` where `W` is a [`ResidentMat`] (`rows`×`cols`, row-major). Each
/// weight row is dequantized once into `scratch` (via the transformer's own
/// per-row dequant kernels), then reduced with `seq_dot`. Bit-identical to
/// bulk-dequant-then-row-wise-`seq_dot` by construction (the STT resident==bulk
/// invariant).
/// FUSED Q8_0 dequant+dot for one weight row, simd128 — the WASM hot path. Computes
/// `sum_b d_b * sum_{j in block b}(qs[j] * x[off+j])` directly from the Q8_0 bytes:
/// 16 int8 are sign-widened i8→i16→i32→f32 in SIMD and multiplied by x, accumulated,
/// then scaled per 32-elem block. NO scalar dequant, NO f32 scratch row (vs the
/// dequant-then-seq_dot path). Block layout = 34 bytes: LE fp16 scale + 32 i8
/// (matches dequantize_q8_0_row / aether's simd-kernel-matvec-q8_0.c). Sound but
/// reassociated vs native scalar (coherence re-verified by argmax on the fleet).
#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn dot_q8_row_simd128(w: &[u8], row_idx: usize, cols: usize, x: &[f32]) -> f32 {
    use core::arch::wasm32::*;
    let blocks_per_row = cols.div_ceil(32);
    let row_ptr = w.as_ptr().add(row_idx * blocks_per_row * 34);
    let xp = x.as_ptr();
    let mut total = 0.0f32;
    for b in 0..blocks_per_row {
        let bp = row_ptr.add(b * 34);
        let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
        let qbase = bp.add(2);
        let xo = b * 32;
        let n = core::cmp::min(32, cols - xo);
        if n == 32 {
            let mut acc = f32x4_splat(0.0);
            let mut c = 0usize;
            while c < 32 {
                let q16 = v128_load(qbase.add(c) as *const v128); // 16 signed int8
                let lo = i16x8_extend_low_i8x16(q16);
                let hi = i16x8_extend_high_i8x16(q16);
                let qf0 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(lo));
                let qf1 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(lo));
                let qf2 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(hi));
                let qf3 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(hi));
                let base = xo + c;
                acc = f32x4_add(acc, f32x4_mul(qf0, v128_load(xp.add(base) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf1, v128_load(xp.add(base + 4) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf2, v128_load(xp.add(base + 8) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf3, v128_load(xp.add(base + 12) as *const v128)));
                c += 16;
            }
            let block_dot = f32x4_extract_lane::<0>(acc) + f32x4_extract_lane::<1>(acc)
                + f32x4_extract_lane::<2>(acc) + f32x4_extract_lane::<3>(acc);
            total += d_val * block_dot;
        } else {
            // Partial trailing block (cols not a multiple of 32): scalar.
            let qs = core::slice::from_raw_parts(qbase as *const i8, n);
            let mut s = 0.0f32;
            for j in 0..n { s += qs[j] as f32 * x[xo + j]; }
            total += d_val * s;
        }
    }
    total
}

/// **Multi-lane FUSED Q8_0 dequant+dot** for one weight row, simd128 — the batched
/// WASM hot path. Reads and unpacks the row's quantized bytes ONCE per 32-elem block
/// (8 f32x4 vectors) and dots them against EVERY lane's activation: the weight
/// read+widen is paid once and amortized across the wave
/// (`Gnosis.WarpBatchAmortization.sharedCost` — one weight read serves the whole wave).
///
/// PER-LANE BIT-IDENTITY: each lane runs the EXACT accumulation sequence of the solo
/// [`dot_q8_row_simd128`] — one fresh `f32x4` accumulator per (block, lane), madds in
/// qf0..qf7 order (= the solo kernel's `c = 0` then `c = 16` iterations), the same
/// lane-0..3 horizontal sum, then `total += d · block_dot` per ascending block, scalar
/// tail blocks in the same j order. Wasm f32 ops are IEEE-deterministic, so identical
/// op sequence ⇒ identical bits: `outs[k] == dot_q8_row_simd128(w, row_idx, cols, xs[k])`
/// exactly. Lanes iterate INSIDE the block so live registers stay ~8 unpacked qf
/// vectors + 1 accumulator regardless of lane count (no per-lane register pressure).
///
/// Replaces the earlier dequant-to-scratch helper (`dequant_q8_row_simd128`), which
/// (a) was only associativity-equal, not bit-equal, to the fused solo kernel, and
/// (b) was missing its `#[target_feature(enable = "simd128")]`, so its v128
/// intrinsics compiled as un-inlined per-op CALLS — the batched base step ran ~10×
/// the solo fused step on the live fleet.
#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn dot_q8_row_simd128_lanes<X: AsRef<[f32]>>(
    w: &[u8],
    row_idx: usize,
    cols: usize,
    xs: &[X],
    outs: &mut [f32],
) {
    use core::arch::wasm32::*;
    let n = xs.len();
    debug_assert!(outs.len() >= n);
    let blocks_per_row = cols.div_ceil(32);
    let row_ptr = w.as_ptr().add(row_idx * blocks_per_row * 34);
    for o in outs[..n].iter_mut() {
        *o = 0.0;
    }
    for b in 0..blocks_per_row {
        let bp = row_ptr.add(b * 34);
        let d_val = f16_to_f32(u16::from_le_bytes([*bp, *bp.add(1)]));
        let qbase = bp.add(2);
        let xo = b * 32;
        let nblk = core::cmp::min(32, cols - xo);
        if nblk == 32 {
            // Unpack the block's 32 int8 ONCE for all lanes: qf0..qf3 mirror the solo
            // kernel's c = 0 iteration, qf4..qf7 its c = 16 iteration.
            let q16a = v128_load(qbase as *const v128); // 16 signed int8
            let loa = i16x8_extend_low_i8x16(q16a);
            let hia = i16x8_extend_high_i8x16(q16a);
            let qf0 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(loa));
            let qf1 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(loa));
            let qf2 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(hia));
            let qf3 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(hia));
            let q16b = v128_load(qbase.add(16) as *const v128);
            let lob = i16x8_extend_low_i8x16(q16b);
            let hib = i16x8_extend_high_i8x16(q16b);
            let qf4 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(lob));
            let qf5 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(lob));
            let qf6 = f32x4_convert_i32x4(i32x4_extend_low_i16x8(hib));
            let qf7 = f32x4_convert_i32x4(i32x4_extend_high_i16x8(hib));
            for k in 0..n {
                let xp = xs[k].as_ref().as_ptr();
                // Same madd order as the solo kernel's two `while c < 32` passes.
                let mut acc = f32x4_splat(0.0);
                acc = f32x4_add(acc, f32x4_mul(qf0, v128_load(xp.add(xo) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf1, v128_load(xp.add(xo + 4) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf2, v128_load(xp.add(xo + 8) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf3, v128_load(xp.add(xo + 12) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf4, v128_load(xp.add(xo + 16) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf5, v128_load(xp.add(xo + 20) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf6, v128_load(xp.add(xo + 24) as *const v128)));
                acc = f32x4_add(acc, f32x4_mul(qf7, v128_load(xp.add(xo + 28) as *const v128)));
                let block_dot = f32x4_extract_lane::<0>(acc) + f32x4_extract_lane::<1>(acc)
                    + f32x4_extract_lane::<2>(acc) + f32x4_extract_lane::<3>(acc);
                outs[k] += d_val * block_dot;
            }
        } else {
            // Partial trailing block (cols not a multiple of 32): scalar, solo order.
            let qs = core::slice::from_raw_parts(qbase as *const i8, nblk);
            for k in 0..n {
                let x = xs[k].as_ref();
                let mut s = 0.0f32;
                for j in 0..nblk {
                    s += qs[j] as f32 * x[xo + j];
                }
                outs[k] += d_val * s;
            }
        }
    }
}

fn matvec_resident(out: &mut [f32], w: &ResidentMat, x: &[f32], scratch: &mut Vec<f32>) {
    debug_assert!(out.len() >= w.rows);
    debug_assert!(x.len() >= w.cols);
    let xs = &x[..w.cols];
    // WASM hot path: fused Q8_0 dequant+dot in simd128 (no scalar dequant, no scratch).
    #[cfg(target_arch = "wasm32")]
    {
        if matches!(w.qtype, QType::Q8_0) {
            let wb: &[u8] = w.bytes.as_ref();
            for i in 0..w.rows {
                out[i] = unsafe { dot_q8_row_simd128(wb, i, w.cols, xs) };
            }
            return;
        }
    }
    // Native (and non-Q8_0 wasm): dequant the row, then the scalar/simd seq_dot.
    if scratch.len() != w.cols {
        scratch.resize(w.cols, 0.0);
    }
    for i in 0..w.rows {
        w.dequant_row_into(i, scratch);
        out[i] = seq_dot(scratch, xs);
    }
}

/// As [`matvec_resident`] but the weight is optional: an absent tensor (the old
/// zero-fill semantics) produces a zero output.
fn matvec_opt(out: &mut [f32], w: Option<&ResidentMat>, x: &[f32], scratch: &mut Vec<f32>) {
    match w {
        Some(m) => matvec_resident(out, m, x, scratch),
        None => out.iter_mut().for_each(|v| *v = 0.0),
    }
}

/// **Width-axis batched matvec** — `outs[k] = W·xs[k]` for every lane `k`, reading and
/// dequantizing each weight ROW exactly ONCE and dotting it against every lane's
/// activation. The shared dequant is the amortization (one weight-read serves the whole
/// wave instead of `n` — `Gnosis.WarpBatchAmortization.sharedCost`). BIT-IDENTICAL to `n`
/// separate `matvec_resident` calls: on native, each lane's `out[i] = seq_dot(dequant(row
/// i), x_k)` is exactly what the single-lane path computes; on wasm, the multi-lane fused
/// Q8 kernel replays the solo fused kernel's accumulation order per lane (see
/// [`dot_q8_row_simd128_lanes`]), so this is parity-safe.
#[allow(dead_code)]
fn matvec_resident_batch(outs: &mut [&mut [f32]], w: &ResidentMat, xs: &[&[f32]], scratch: &mut Vec<f32>) {
    let n = xs.len();
    debug_assert_eq!(outs.len(), n);
    // WASM hot path: multi-lane FUSED Q8_0 dequant+dot — the row's quantized bytes are
    // read+widened ONCE and dotted against every lane (no f32 scratch row, no
    // store/reload per lane), each lane bit-identical to the solo fused kernel. The
    // shared read is the width-axis amortization; the fusion is the ~6× solo-kernel win
    // the batch path previously lost.
    #[cfg(target_arch = "wasm32")]
    {
        if matches!(w.qtype, QType::Q8_0) {
            let wb: &[u8] = w.bytes.as_ref();
            for x in xs {
                debug_assert!(x.len() >= w.cols);
            }
            // Width-1 wave: the multi-lane kernel is bit-identical to the solo fused
            // kernel, so skip its lane indirection (~12% on V8) and call solo directly.
            if n == 1 {
                let x0 = &xs[0][..w.cols];
                for i in 0..w.rows {
                    outs[0][i] = unsafe { dot_q8_row_simd128(wb, i, w.cols, x0) };
                }
                return;
            }
            // Reuse the caller's scratch as the per-row lane-dot buffer.
            if scratch.len() != n {
                scratch.resize(n, 0.0);
            }
            for i in 0..w.rows {
                unsafe { dot_q8_row_simd128_lanes(wb, i, w.cols, xs, scratch) };
                for k in 0..n {
                    outs[k][i] = scratch[k];
                }
            }
            return;
        }
    }
    if scratch.len() != w.cols {
        scratch.resize(w.cols, 0.0);
    }
    for i in 0..w.rows {
        w.dequant_row_into(i, scratch); // ONE dequant/read per row, shared across all lanes
        for k in 0..n {
            outs[k][i] = seq_dot(scratch, &xs[k][..w.cols]);
        }
    }
}

/// Batched [`matvec_opt`]: zero-fills all lanes for an absent weight, else batches.
#[allow(dead_code)]
fn matvec_opt_batch(outs: &mut [&mut [f32]], w: Option<&ResidentMat>, xs: &[&[f32]], scratch: &mut Vec<f32>) {
    match w {
        Some(m) => matvec_resident_batch(outs, m, xs, scratch),
        None => outs.iter_mut().for_each(|o| o.iter_mut().for_each(|v| *v = 0.0)),
    }
}

/// Vec-of-Vec ergonomic wrapper over the batched-kernel call shape. Formerly it
/// collected TWO throwaway slice-ref Vecs (`Vec<&mut [f32]>` + `Vec<&[f32]>`) on
/// EVERY call (~14 calls/layer ⇒ ~336 heap allocs/token at width-1 — the measured
/// ~1.3× width-1 wave gap vs solo). Now: a width-1 wave dispatches straight to the
/// SOLO [`matvec_resident`] on lane 0's flat buffers (bit-identical — the batched
/// kernels replay the solo accumulation order per lane, see
/// [`matvec_resident_batch`]), and the n≥2 path indexes the Vec-of-Vecs directly
/// (the lanes kernel is generic over `AsRef<[f32]>`), allocating nothing.
#[allow(dead_code)]
fn bmatvec(outs: &mut [Vec<f32>], w: Option<&ResidentMat>, ins: &[Vec<f32>], scratch: &mut Vec<f32>) {
    let n = ins.len();
    debug_assert_eq!(outs.len(), n);
    let Some(m) = w else {
        outs.iter_mut().for_each(|o| o.iter_mut().for_each(|v| *v = 0.0));
        return;
    };
    // Width-1 wave: the solo matvec IS the batch math at n==1 — skip all lane plumbing.
    if n == 1 {
        matvec_resident(&mut outs[0], m, &ins[0], scratch);
        return;
    }
    // WASM hot path: multi-lane FUSED Q8_0 dequant+dot — identical kernel + order as
    // [`matvec_resident_batch`] (each lane bit-identical to the solo fused kernel).
    #[cfg(target_arch = "wasm32")]
    {
        if matches!(m.qtype, QType::Q8_0) {
            let wb: &[u8] = m.bytes.as_ref();
            for x in ins {
                debug_assert!(x.len() >= m.cols);
            }
            if scratch.len() != n {
                scratch.resize(n, 0.0);
            }
            for i in 0..m.rows {
                unsafe { dot_q8_row_simd128_lanes(wb, i, m.cols, ins, scratch) };
                for k in 0..n {
                    outs[k][i] = scratch[k];
                }
            }
            return;
        }
    }
    if scratch.len() != m.cols {
        scratch.resize(m.cols, 0.0);
    }
    for i in 0..m.rows {
        m.dequant_row_into(i, scratch); // ONE dequant/read per row, shared across all lanes
        for k in 0..n {
            outs[k][i] = seq_dot(scratch, &ins[k][..m.cols]);
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Batch scratch arenas (K2: kill the width-axis alloc churn)
// ─────────────────────────────────────────────────────────────────────────────
//
// The batched layer halves used to allocate ~22 `vec![vec![0.0; d]; n]`
// Vec-of-Vec intermediates per call, plus per-head `kk_a`/`tmp` INSIDE the WKV
// head loop (320 more at n=4/40 heads) — ~460 allocs per layer per call, ~5% of
// the marginal-lane cost at d=2560 and a hard floor under the elementwise
// sections. They are replaced by flat `[n·dim]` arenas that live in a
// thread-local and are only ever GROWN (capacity persists across calls; a wave
// step allocates NOTHING at steady state).
//
// Bit-exactness license: every arena region is FULLY WRITTEN before it is read
// (token-shift/elementwise loops write all `n·d` slots; `bmatvec_flat` writes
// or zero-fills every lane row), so skipping the `vec!` zero-init cannot leak a
// previous call's values into any output. Arithmetic order is untouched — the
// same loops run over flat offsets instead of nested Vecs.
//
// A thread-local (same pattern as `model.rs`'s dequant scratch) rather than a
// pipeline field keeps `forward_one_batch`/`stream_layer_*_batch` at `&self`
// (re-entrant hosts) without a RefCell in the Sync pipeline. The two layer
// halves borrow it one at a time — never nested.

/// Max lanes served by the STACK-allocated slice-view tables below. Wider
/// waves still work (heap-fallback view Vec); the fleet's widths are 2–8.
const MAX_WAVE_LANES: usize = 16;

#[derive(Default)]
struct TimeMixBatchScratch {
    // token-shift outputs, [n*d] each
    xr: Vec<f32>,
    xw: Vec<f32>,
    xk: Vec<f32>,
    xv: Vec<f32>,
    xa: Vec<f32>,
    xg: Vec<f32>,
    // projections + dynamics
    r: Vec<f32>,       // [n*d]
    k: Vec<f32>,       // [n*d]
    v: Vec<f32>,       // [n*d]
    w1_out: Vec<f32>,  // [n*lrw]
    w_dyn: Vec<f32>,   // [n*d]
    w_decay: Vec<f32>, // [n*d]
    a1_out: Vec<f32>,  // [n*lra]
    a2_out: Vec<f32>,  // [n*d]
    a: Vec<f32>,       // [n*d]
    kk: Vec<f32>,      // [n*d]
    v1_out: Vec<f32>,  // [n*lrv]
    v2_out: Vec<f32>,  // [n*d]
    output: Vec<f32>,  // [n*d]
    g1_out: Vec<f32>,  // [n*gi]
    gate: Vec<f32>,    // [n*d]
    out: Vec<f32>,     // [n*d] final projected result (the wrapper's residual add)
    // per-head WKV temporaries, [hs] each — hoisted out of the 40-head loop
    kk_a: Vec<f32>,
    tmp: Vec<f32>,
    // per-row dequant / per-row lane-dot scratch for the batched matvecs
    mv: Vec<f32>,
}

#[derive(Default)]
struct ChannelMixBatchScratch {
    xk: Vec<f32>,  // [n*d]
    kbuf: Vec<f32>, // [n*ffn_inner]
    out: Vec<f32>, // [n*d]
    mv: Vec<f32>,
}

#[derive(Default)]
struct BatchScratch {
    /// The wrappers' per-lane LayerNorm arena, [n*d] (feeds the halves as input).
    normed: Vec<f32>,
    tm: TimeMixBatchScratch,
    cm: ChannelMixBatchScratch,
}

thread_local! {
    static BATCH_SCRATCH: std::cell::RefCell<BatchScratch> =
        std::cell::RefCell::new(BatchScratch::default());
}

/// Grow-only resize: never zeroes live regions, never shrinks (capacity is the
/// point). New tail slots are zero, but every consumer fully writes its region
/// before reading (see the module comment above).
#[inline]
fn grow(v: &mut Vec<f32>, len: usize) {
    if v.len() < len {
        v.resize(len, 0.0);
    }
}

/// Flat-arena twin of [`bmatvec`]: `out[k*out_dim..][..rows] = W · ins[k*in_dim..][..cols]`
/// per lane, one weight read/dequant per row for the whole wave. Same kernels,
/// same per-row/per-lane order as [`bmatvec`] → bit-identical; the only change
/// is where the lane buffers live (one flat arena instead of n heap Vecs).
#[allow(dead_code)]
fn bmatvec_flat(
    out: &mut [f32],
    out_dim: usize,
    w: Option<&ResidentMat>,
    ins: &[f32],
    in_dim: usize,
    n: usize,
    mv: &mut Vec<f32>,
) {
    let Some(m) = w else {
        // Absent weight → zero every lane's output row (old zero-fill semantics).
        for k in 0..n {
            out[k * out_dim..k * out_dim + out_dim].iter_mut().for_each(|v| *v = 0.0);
        }
        return;
    };
    debug_assert!(m.rows <= out_dim);
    debug_assert!(m.cols <= in_dim);
    // Width-1 wave: the solo matvec IS the batch math at n==1.
    if n == 1 {
        matvec_resident(&mut out[..out_dim], m, &ins[..in_dim], mv);
        return;
    }
    // Per-lane input views (stack table; heap only past MAX_WAVE_LANES).
    let mut view_store: [&[f32]; MAX_WAVE_LANES] = [&[]; MAX_WAVE_LANES];
    let heap_views: Vec<&[f32]>;
    let xs: &[&[f32]] = if n <= MAX_WAVE_LANES {
        for (k, slot) in view_store.iter_mut().enumerate().take(n) {
            *slot = &ins[k * in_dim..k * in_dim + m.cols];
        }
        &view_store[..n]
    } else {
        heap_views = (0..n).map(|k| &ins[k * in_dim..k * in_dim + m.cols]).collect();
        &heap_views
    };
    // WASM hot path: multi-lane FUSED Q8_0 dequant+dot (each lane bit-identical
    // to the solo fused kernel — see [`dot_q8_row_simd128_lanes`]).
    #[cfg(target_arch = "wasm32")]
    {
        if matches!(m.qtype, QType::Q8_0) {
            let wb: &[u8] = m.bytes.as_ref();
            if mv.len() != n {
                mv.resize(n, 0.0);
            }
            for i in 0..m.rows {
                unsafe { dot_q8_row_simd128_lanes(wb, i, m.cols, xs, mv) };
                for k in 0..n {
                    out[k * out_dim + i] = mv[k];
                }
            }
            return;
        }
    }
    if mv.len() != m.cols {
        mv.resize(m.cols, 0.0);
    }
    for i in 0..m.rows {
        m.dequant_row_into(i, mv); // ONE dequant/read per row, shared across all lanes
        for k in 0..n {
            out[k * out_dim + i] = seq_dot(mv, xs[k]);
        }
    }
}

/// Load a resident matrix if present, else `None` (old zero-fill semantics).
fn resident_opt(
    backend: &dyn WeightBackend,
    name: &str,
    rows: usize,
    cols: usize,
) -> Option<ResidentMat> {
    if backend.has_tensor(name) {
        Some(ResidentMat::from_backend(backend, name, rows, cols))
    } else {
        None
    }
}

/// First present alias → resident matrix, else `None`. Mirrors `fetch_first`
/// for the matrices that carry both Goose and legacy tensor names.
fn resident_first(
    backend: &dyn WeightBackend,
    names: &[&str],
    rows: usize,
    cols: usize,
) -> Option<ResidentMat> {
    for nm in names {
        if backend.has_tensor(nm) {
            return Some(ResidentMat::from_backend(backend, nm, rows, cols));
        }
    }
    None
}

#[allow(dead_code)]
fn rms_norm(x: &mut [f32], w: &[f32], eps: f32) {
    let ms = x.iter().map(|v| v * v).sum::<f32>() / x.len() as f32;
    let inv = 1.0 / (ms + eps).sqrt();
    for (v, g) in x.iter_mut().zip(w.iter()) {
        *v = *v * inv * g;
    }
}

fn layer_norm(x: &[f32], gain: &[f32], bias: &[f32]) -> Vec<f32> {
    let mut out = vec![0.0f32; x.len()];
    layer_norm_into(x, gain, bias, &mut out);
    out
}

/// [`layer_norm`] into a caller-provided buffer (the batch wrappers' flat
/// `normed` arena) — identical arithmetic, no allocation.
fn layer_norm_into(x: &[f32], gain: &[f32], bias: &[f32], out: &mut [f32]) {
    let n = x.len() as f32;
    let mean = x.iter().sum::<f32>() / n;
    let var = x.iter().map(|v| (v - mean) * (v - mean)).sum::<f32>() / n;
    let inv = 1.0 / (var + 1e-5).sqrt();
    for i in 0..x.len() {
        out[i] = gain[i] * (x[i] - mean) * inv + bias[i];
    }
}

fn group_norm_in_place(x: &mut [f32], n_groups: usize, gain: &[f32], bias: &[f32]) {
    let group_size = x.len() / n_groups;
    let eps = 64e-5f32;
    for g in 0..n_groups {
        let off = g * group_size;
        let slice = &mut x[off..off + group_size];
        let mean = slice.iter().sum::<f32>() / group_size as f32;
        let var = slice.iter().map(|v| (v - mean) * (v - mean)).sum::<f32>() / group_size as f32;
        let inv = 1.0 / (var + eps).sqrt();
        for (i, v) in slice.iter_mut().enumerate() {
            *v = gain[off + i] * (*v - mean) * inv + bias[off + i];
        }
    }
}

/// Normalize a per-head slice to unit norm (used for kk).
fn normalize_per_head(v: &mut [f32], n_heads: usize, head_size: usize) {
    for h in 0..n_heads {
        let off = h * head_size;
        let norm = v[off..off + head_size]
            .iter()
            .map(|x| x * x)
            .sum::<f32>()
            .sqrt()
            + 1e-12;
        for i in 0..head_size {
            v[off + i] /= norm;
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// K4: shared elementwise kernels — solo AND batch call the SAME fns, so batch==
// solo parity holds by shared code. Every kernel is PURE ELEMENTWISE (no
// reductions), so vectorizing lanes cannot reorder any accumulation: per
// element, the f32x4 lane executes the IDENTICAL op sequence as the scalar
// loop, and wasm f32 ops are IEEE-deterministic ⇒ bit-exact. The reductions
// (the two 64-dots in WKV, norms, rk_sum) and the libm transcendentals
// (exp/tanh/sigmoid) deliberately STAY scalar — vectorizing those changes
// accumulation order / value, which is absolute output drift.
//
// wasm32: per-function `#[target_feature(enable = "simd128")]` (NOT crate-wide
// — the dot_q8 lesson: a missing attribute compiles v128 intrinsics as
// un-inlined per-op calls), scalar tail in the same formula. Native: scalar.
// ─────────────────────────────────────────────────────────────────────────────

/// `out[i] = x[i] + (shift[i] − x[i]) · mix[i]` — the token-shift lerp.
#[inline]
fn token_shift_mix(out: &mut [f32], x: &[f32], shift: &[f32], mix: &[f32]) {
    let n = out.len();
    debug_assert!(x.len() >= n && shift.len() >= n && mix.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        token_shift_mix_simd128(out, x, shift, mix)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for i in 0..n {
        let xx = shift[i] - x[i];
        out[i] = x[i] + xx * mix[i];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn token_shift_mix_simd128(out: &mut [f32], x: &[f32], shift: &[f32], mix: &[f32]) {
    use core::arch::wasm32::*;
    let n = out.len();
    let (op, xp, sp, mp) = (out.as_mut_ptr(), x.as_ptr(), shift.as_ptr(), mix.as_ptr());
    let mut i = 0usize;
    while i + 4 <= n {
        let xv = v128_load(xp.add(i) as *const v128);
        let xx = f32x4_sub(v128_load(sp.add(i) as *const v128), xv);
        let r = f32x4_add(xv, f32x4_mul(xx, v128_load(mp.add(i) as *const v128)));
        v128_store(op.add(i) as *mut v128, r);
        i += 4;
    }
    while i < n {
        let xx = *sp.add(i) - *xp.add(i);
        *op.add(i) = *xp.add(i) + xx * *mp.add(i);
        i += 1;
    }
}

/// `out[i] = a[i] · b[i]` (the `kk = k · k_k` product).
#[inline]
fn mul_into(out: &mut [f32], a: &[f32], b: &[f32]) {
    let n = out.len();
    debug_assert!(a.len() >= n && b.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        mul_into_simd128(out, a, b)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for i in 0..n {
        out[i] = a[i] * b[i];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn mul_into_simd128(out: &mut [f32], a: &[f32], b: &[f32]) {
    use core::arch::wasm32::*;
    let n = out.len();
    let (op, ap, bp) = (out.as_mut_ptr(), a.as_ptr(), b.as_ptr());
    let mut i = 0usize;
    while i + 4 <= n {
        let r = f32x4_mul(v128_load(ap.add(i) as *const v128), v128_load(bp.add(i) as *const v128));
        v128_store(op.add(i) as *mut v128, r);
        i += 4;
    }
    while i < n {
        *op.add(i) = *ap.add(i) * *bp.add(i);
        i += 1;
    }
}

/// `out[i] *= g[i]` (the output gating).
#[inline]
fn mul_assign(out: &mut [f32], g: &[f32]) {
    let n = out.len();
    debug_assert!(g.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        mul_assign_simd128(out, g)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for i in 0..n {
        out[i] *= g[i];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn mul_assign_simd128(out: &mut [f32], g: &[f32]) {
    use core::arch::wasm32::*;
    let n = out.len();
    let (op, gp) = (out.as_mut_ptr(), g.as_ptr());
    let mut i = 0usize;
    while i + 4 <= n {
        let r = f32x4_mul(v128_load(op.add(i) as *const v128), v128_load(gp.add(i) as *const v128));
        v128_store(op.add(i) as *mut v128, r);
        i += 4;
    }
    while i < n {
        *op.add(i) *= *gp.add(i);
        i += 1;
    }
}

/// `x[i] += delta[i]` (the residual adds).
#[inline]
fn add_assign(x: &mut [f32], delta: &[f32]) {
    let n = x.len();
    debug_assert!(delta.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        add_assign_simd128(x, delta)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for i in 0..n {
        x[i] += delta[i];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn add_assign_simd128(x: &mut [f32], delta: &[f32]) {
    use core::arch::wasm32::*;
    let n = x.len();
    let (xp, dp) = (x.as_mut_ptr(), delta.as_ptr());
    let mut i = 0usize;
    while i + 4 <= n {
        let r = f32x4_add(v128_load(xp.add(i) as *const v128), v128_load(dp.add(i) as *const v128));
        v128_store(xp.add(i) as *mut v128, r);
        i += 4;
    }
    while i < n {
        *xp.add(i) += *dp.add(i);
        i += 1;
    }
}

/// `out[i] += c · v[i]` (the r_k bonus fan-out).
#[inline]
fn axpy_const(out: &mut [f32], c: f32, v: &[f32]) {
    let n = out.len();
    debug_assert!(v.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        axpy_const_simd128(out, c, v)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for i in 0..n {
        out[i] += c * v[i];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn axpy_const_simd128(out: &mut [f32], c: f32, v: &[f32]) {
    use core::arch::wasm32::*;
    let n = out.len();
    let (op, vp) = (out.as_mut_ptr(), v.as_ptr());
    let cv = f32x4_splat(c);
    let mut i = 0usize;
    while i + 4 <= n {
        let r = f32x4_add(
            v128_load(op.add(i) as *const v128),
            f32x4_mul(cv, v128_load(vp.add(i) as *const v128)),
        );
        v128_store(op.add(i) as *mut v128, r);
        i += 4;
    }
    while i < n {
        *op.add(i) += c * *vp.add(i);
        i += 1;
    }
}

/// `k[i] *= 1 + (a[i] − 1) · k_a[i]` (the key in-context-learning-rate adjust).
#[inline]
fn k_adjust(k: &mut [f32], a: &[f32], ka: &[f32]) {
    let n = k.len();
    debug_assert!(a.len() >= n && ka.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        k_adjust_simd128(k, a, ka)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for i in 0..n {
        k[i] *= 1.0 + (a[i] - 1.0) * ka[i];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn k_adjust_simd128(k: &mut [f32], a: &[f32], ka: &[f32]) {
    use core::arch::wasm32::*;
    let n = k.len();
    let (kp, ap, kap) = (k.as_mut_ptr(), a.as_ptr(), ka.as_ptr());
    let one = f32x4_splat(1.0);
    let mut i = 0usize;
    while i + 4 <= n {
        let am1 = f32x4_sub(v128_load(ap.add(i) as *const v128), one);
        let g = f32x4_add(one, f32x4_mul(am1, v128_load(kap.add(i) as *const v128)));
        let r = f32x4_mul(v128_load(kp.add(i) as *const v128), g);
        v128_store(kp.add(i) as *mut v128, r);
        i += 4;
    }
    while i < n {
        *kp.add(i) *= 1.0 + (*ap.add(i) - 1.0) * *kap.add(i);
        i += 1;
    }
}

/// `v[i] = max(v[i], 0)²` — the channel-mix squared ReLU. The SIMD max is
/// `pmax(v, 0) = (0 < v) ? v : 0`, which matches Rust's NaN-ignoring
/// `f32::max(v, 0.0)` (NaN → 0) and squares ±0 to +0 either way.
#[inline]
fn relu_sq(v: &mut [f32]) {
    let n = v.len();
    #[cfg(target_arch = "wasm32")]
    unsafe {
        relu_sq_simd128(v)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for x in v.iter_mut().take(n) {
        *x = x.max(0.0).powi(2);
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn relu_sq_simd128(v: &mut [f32]) {
    use core::arch::wasm32::*;
    let n = v.len();
    let vp = v.as_mut_ptr();
    let zero = f32x4_splat(0.0);
    let mut i = 0usize;
    while i + 4 <= n {
        let m = f32x4_pmax(v128_load(vp.add(i) as *const v128), zero);
        v128_store(vp.add(i) as *mut v128, f32x4_mul(m, m));
        i += 4;
    }
    while i < n {
        let m = (*vp.add(i)).max(0.0);
        *vp.add(i) = m * m;
        i += 1;
    }
}

/// WKV-7 per-head state-ROW update (row i of one head's [hs × hs] state):
/// `state[j] = state[j]·w_decay[j] + tmp_i·kk_a[j] + v_i·k[j]` — the decay/
/// delta-rule/write superposition, elementwise over j (`((s·w) + (t·ka)) + (v·k)`,
/// the scalar's exact op order per element). The 10–15% scalar-WKV section of
/// the marginal-lane cost model lives here.
#[inline]
fn wkv_row_update(state_row: &mut [f32], wd: &[f32], kk_a: &[f32], k: &[f32], tmp_i: f32, v_i: f32) {
    let n = state_row.len();
    debug_assert!(wd.len() >= n && kk_a.len() >= n && k.len() >= n);
    #[cfg(target_arch = "wasm32")]
    unsafe {
        wkv_row_update_simd128(state_row, wd, kk_a, k, tmp_i, v_i)
    }
    #[cfg(not(target_arch = "wasm32"))]
    for j in 0..n {
        state_row[j] = state_row[j] * wd[j] + tmp_i * kk_a[j] + v_i * k[j];
    }
}

#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn wkv_row_update_simd128(
    state_row: &mut [f32],
    wd: &[f32],
    kk_a: &[f32],
    k: &[f32],
    tmp_i: f32,
    v_i: f32,
) {
    use core::arch::wasm32::*;
    let n = state_row.len();
    let (sp, wp, kap, kp) = (state_row.as_mut_ptr(), wd.as_ptr(), kk_a.as_ptr(), k.as_ptr());
    let tv = f32x4_splat(tmp_i);
    let vv = f32x4_splat(v_i);
    let mut j = 0usize;
    while j + 4 <= n {
        let decayed = f32x4_mul(v128_load(sp.add(j) as *const v128), v128_load(wp.add(j) as *const v128));
        let with_delta = f32x4_add(decayed, f32x4_mul(tv, v128_load(kap.add(j) as *const v128)));
        let written = f32x4_add(with_delta, f32x4_mul(vv, v128_load(kp.add(j) as *const v128)));
        v128_store(sp.add(j) as *mut v128, written);
        j += 4;
    }
    while j < n {
        *sp.add(j) = *sp.add(j) * *wp.add(j) + tmp_i * *kap.add(j) + v_i * *kp.add(j);
        j += 1;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// WKV-7 time-mixing forward (single token, all heads)
// ─────────────────────────────────────────────────────────────────────────────

struct TimeMixWeights<'a> {
    // Per-channel vectors (small) stay dense f32.
    mix_r: &'a [f32],
    mix_w: &'a [f32],
    mix_k: &'a [f32],
    mix_v: &'a [f32],
    mix_a: &'a [f32],
    mix_g: &'a [f32],
    // Projection matrices stay RESIDENT in source quant (Q8_0/F16/F32) and are
    // dequantized per-row inside the matvec. `Option` preserves the old zero-
    // fill-when-absent semantics.
    r_weight: Option<&'a ResidentMat>,
    k_weight: Option<&'a ResidentMat>,
    v_weight: Option<&'a ResidentMat>,
    o_weight: Option<&'a ResidentMat>,
    w0: &'a [f32],
    w1: Option<&'a ResidentMat>,
    w2: Option<&'a ResidentMat>,
    a0: &'a [f32],
    a1: Option<&'a ResidentMat>,
    a2: Option<&'a ResidentMat>,
    v0: &'a [f32],
    v1: Option<&'a ResidentMat>,
    v2: Option<&'a ResidentMat>,
    k_k: &'a [f32],
    k_a: &'a [f32],
    r_k: &'a [f32],
    g1: Option<&'a ResidentMat>,
    g2: Option<&'a ResidentMat>,
    ln_gain: &'a [f32],
    ln_bias: &'a [f32],
}

fn time_mix7(
    x: &[f32],
    layer_idx: usize,
    state: &mut RWKV7LayerState,
    // Shared across ALL layers within one token step: layer 0 seeds it, layers
    // 1+ mix toward it. Per-layer state must NOT own v_first — that would hide
    // layer 0's value from every later layer and silently disable versioning.
    v_first: &mut Vec<f32>,
    w: &TimeMixWeights<'_>,
    cfg: &RWKV7Config,
) -> Vec<f32> {
    let d = cfg.hidden_dim;
    let lrw = cfg.low_rank_w;
    let lra = cfg.low_rank_a;
    let lrv = cfg.low_rank_v;
    let gi = cfg.gate_inner;

    // Token-shift mixing (K4 shared elementwise kernel — six lerps; `xx` is
    // recomputed per pass from the same inputs, value-identical to the old
    // single fused loop).
    let mut xr = vec![0.0f32; d];
    let mut xw_mix = vec![0.0f32; d];
    let mut xk = vec![0.0f32; d];
    let mut xv_mix = vec![0.0f32; d];
    let mut xa = vec![0.0f32; d];
    let mut xg = vec![0.0f32; d];
    token_shift_mix(&mut xr, x, &state.shift_x, w.mix_r);
    token_shift_mix(&mut xw_mix, x, &state.shift_x, w.mix_w);
    token_shift_mix(&mut xk, x, &state.shift_x, w.mix_k);
    token_shift_mix(&mut xv_mix, x, &state.shift_x, w.mix_v);
    token_shift_mix(&mut xa, x, &state.shift_x, w.mix_a);
    token_shift_mix(&mut xg, x, &state.shift_x, w.mix_g);

    // Reused per-row dequant scratch for all resident matvecs in this step.
    let mut scratch: Vec<f32> = Vec::new();

    // Main projections R, K, V
    let mut r = vec![0.0f32; d];
    matvec_opt(&mut r, w.r_weight, &xr, &mut scratch);
    let mut k = vec![0.0f32; d];
    matvec_opt(&mut k, w.k_weight, &xk, &mut scratch);
    let mut v = vec![0.0f32; d];
    matvec_opt(&mut v, w.v_weight, &xv_mix, &mut scratch);

    // Dynamic time decay: w = exp(-0.606531 * sigmoid(w0 + tanh(xw@w1)@w2))
    let mut w1_out = vec![0.0f32; lrw];
    matvec_opt(&mut w1_out, w.w1, &xw_mix, &mut scratch);
    for v_ in &mut w1_out {
        *v_ = v_.tanh();
    }
    let mut w_dyn = vec![0.0f32; d];
    matvec_opt(&mut w_dyn, w.w2, &w1_out, &mut scratch);
    let mut w_decay = vec![0.0f32; d];
    for i in 0..d {
        w_decay[i] = (-0.606531 * sigmoid(w.w0[i] + w_dyn[i])).exp();
    }

    // Dynamic attention: a = sigmoid(a0 + (xa@a1)@a2)
    let mut a1_out = vec![0.0f32; lra];
    matvec_opt(&mut a1_out, w.a1, &xa, &mut scratch);
    let mut a2_out = vec![0.0f32; d];
    matvec_opt(&mut a2_out, w.a2, &a1_out, &mut scratch);
    let mut a = vec![0.0f32; d];
    for i in 0..d {
        a[i] = sigmoid(w.a0[i] + a2_out[i]);
    }

    // Key adjustment: kk = normalize(k * k_k per head)
    let mut kk = vec![0.0f32; d];
    mul_into(&mut kk, &k, w.k_k);
    normalize_per_head(&mut kk, cfg.n_heads, cfg.head_size);

    // k = k * (1 + (a - 1) * k_a)
    k_adjust(&mut k, &a, w.k_a);

    // Value versioning (cross-layer): layer 0 seeds the shared v_first; later
    // layers blend toward it via the v-lora gate.
    if layer_idx == 0 {
        *v_first = v.clone();
    } else if !v_first.is_empty() {
        let mut v1_out = vec![0.0f32; lrv];
        matvec_opt(&mut v1_out, w.v1, &xv_mix, &mut scratch);
        let mut v2_out = vec![0.0f32; d];
        matvec_opt(&mut v2_out, w.v2, &v1_out, &mut scratch);
        for i in 0..d {
            let vg = sigmoid(w.v0[i] + v2_out[i]);
            v[i] = v[i] + (v_first[i] - v[i]) * vg;
        }
    }

    // WKV-7 state update (per head)
    let mut output = vec![0.0f32; d];
    let n_heads = cfg.n_heads;
    let hs = cfg.head_size;

    for h in 0..n_heads {
        let h_off = h * hs;
        let s_off = h * hs * hs;

        // kk*a for this head
        let mut kk_a = vec![0.0f32; hs];
        for i in 0..hs {
            kk_a[i] = kk[h_off + i] * a[h_off + i];
        }

        // tmp = state @ (-kk)
        let mut tmp = vec![0.0f32; hs];
        for i in 0..hs {
            let mut sum = 0.0f32;
            for l in 0..hs {
                sum += state.wkv[s_off + i * hs + l] * -kk[h_off + l];
            }
            tmp[i] = sum;
        }

        // state = state * w_decay + tmp ⊗ kk_a + v ⊗ k (K4 shared row kernel)
        for i in 0..hs {
            let row = s_off + i * hs;
            wkv_row_update(
                &mut state.wkv[row..row + hs],
                &w_decay[h_off..h_off + hs],
                &kk_a,
                &k[h_off..h_off + hs],
                tmp[i],
                v[h_off + i],
            );
        }

        // output = state @ r
        for i in 0..hs {
            let mut sum = 0.0f32;
            for j in 0..hs {
                sum += state.wkv[s_off + i * hs + j] * r[h_off + j];
            }
            output[h_off + i] = sum;
        }
    }

    // Group norm
    group_norm_in_place(&mut output, n_heads, w.ln_gain, w.ln_bias);

    // r_k bonus: (r * k * r_k).sum(per head) * v — the sum STAYS scalar (it is
    // a reduction); only the elementwise fan-out is the K4 shared kernel.
    for h in 0..n_heads {
        let h_off = h * hs;
        let mut rk_sum = 0.0f32;
        for i in 0..hs {
            rk_sum += r[h_off + i] * k[h_off + i] * w.r_k[h_off + i];
        }
        axpy_const(&mut output[h_off..h_off + hs], rk_sum, &v[h_off..h_off + hs]);
    }

    // Gate: g = sigmoid(xg@g1)@g2
    let mut g1_out = vec![0.0f32; gi];
    matvec_opt(&mut g1_out, w.g1, &xg, &mut scratch);
    for v_ in &mut g1_out {
        *v_ = sigmoid(*v_);
    }
    let mut gate = vec![0.0f32; d];
    matvec_opt(&mut gate, w.g2, &g1_out, &mut scratch);
    mul_assign(&mut output, &gate);

    // Output projection
    let mut projected = vec![0.0f32; d];
    matvec_opt(&mut projected, w.o_weight, &output, &mut scratch);

    // Update shift state
    state.shift_x.copy_from_slice(x);

    projected
}

/// **Batched WKV-7 time-mix** over `n` lanes. Bit-identical, per lane, to `n` separate
/// [`time_mix7`] calls — every elementwise op and the WKV recurrence are the SAME scalar
/// arithmetic per lane; only the weight reads are shared via [`bmatvec_flat`]
/// (one page+dequant per row serves the whole wave). This is the width-axis amortization
/// the warp exists for. Parity is gated by the `rwkv7_batched_*_parity` tests.
///
/// All intermediates live in the caller's [`TimeMixBatchScratch`] flat arenas
/// (K2 — zero allocations at steady state; formerly ~22 Vec-of-Vec buffers plus
/// per-head `kk_a`/`tmp` allocations INSIDE the 40-head WKV loop). Returns the
/// projected outputs as `&s.out[..n*d]` (lane k at `[k*d..(k+1)*d]`).
#[allow(dead_code)]
fn time_mix7_batch<'s>(
    xs: &[&[f32]],
    layer_idx: usize,
    states: &mut [RWKV7LayerState],
    v_firsts: &mut [Vec<f32>],
    w: &TimeMixWeights<'_>,
    cfg: &RWKV7Config,
    s: &'s mut TimeMixBatchScratch,
) -> &'s [f32] {
    let n = xs.len();
    let d = cfg.hidden_dim;
    let lrw = cfg.low_rank_w;
    let lra = cfg.low_rank_a;
    let lrv = cfg.low_rank_v;
    let gi = cfg.gate_inner;
    let n_heads = cfg.n_heads;
    let hs = cfg.head_size;
    // Grow-only arenas: every region is fully written before read (see the
    // BatchScratch module comment), so no zeroing is needed for bit-exactness.
    grow(&mut s.xr, n * d);
    grow(&mut s.xw, n * d);
    grow(&mut s.xk, n * d);
    grow(&mut s.xv, n * d);
    grow(&mut s.xa, n * d);
    grow(&mut s.xg, n * d);
    grow(&mut s.r, n * d);
    grow(&mut s.k, n * d);
    grow(&mut s.v, n * d);
    grow(&mut s.w1_out, n * lrw);
    grow(&mut s.w_dyn, n * d);
    grow(&mut s.w_decay, n * d);
    grow(&mut s.a1_out, n * lra);
    grow(&mut s.a2_out, n * d);
    grow(&mut s.a, n * d);
    grow(&mut s.kk, n * d);
    grow(&mut s.output, n * d);
    grow(&mut s.g1_out, n * gi);
    grow(&mut s.gate, n * d);
    grow(&mut s.out, n * d);
    grow(&mut s.kk_a, hs);
    grow(&mut s.tmp, hs);

    // Token-shift mixing (per lane; K4 shared elementwise kernel).
    for k in 0..n {
        let o = k * d;
        let sh = &states[k].shift_x;
        token_shift_mix(&mut s.xr[o..o + d], xs[k], sh, w.mix_r);
        token_shift_mix(&mut s.xw[o..o + d], xs[k], sh, w.mix_w);
        token_shift_mix(&mut s.xk[o..o + d], xs[k], sh, w.mix_k);
        token_shift_mix(&mut s.xv[o..o + d], xs[k], sh, w.mix_v);
        token_shift_mix(&mut s.xa[o..o + d], xs[k], sh, w.mix_a);
        token_shift_mix(&mut s.xg[o..o + d], xs[k], sh, w.mix_g);
    }

    // Main projections R, K, V (batched — one weight read per row, all lanes).
    bmatvec_flat(&mut s.r, d, w.r_weight, &s.xr, d, n, &mut s.mv);
    bmatvec_flat(&mut s.k, d, w.k_weight, &s.xk, d, n, &mut s.mv);
    bmatvec_flat(&mut s.v, d, w.v_weight, &s.xv, d, n, &mut s.mv);

    // Dynamic time decay: w = exp(-0.606531 * sigmoid(w0 + tanh(xw@w1)@w2))
    bmatvec_flat(&mut s.w1_out, lrw, w.w1, &s.xw, d, n, &mut s.mv);
    for v_ in &mut s.w1_out[..n * lrw] {
        *v_ = v_.tanh();
    }
    bmatvec_flat(&mut s.w_dyn, d, w.w2, &s.w1_out, lrw, n, &mut s.mv);
    for k in 0..n {
        let o = k * d;
        for i in 0..d {
            s.w_decay[o + i] = (-0.606531 * sigmoid(w.w0[i] + s.w_dyn[o + i])).exp();
        }
    }

    // Dynamic attention: a = sigmoid(a0 + (xa@a1)@a2)
    bmatvec_flat(&mut s.a1_out, lra, w.a1, &s.xa, d, n, &mut s.mv);
    bmatvec_flat(&mut s.a2_out, d, w.a2, &s.a1_out, lra, n, &mut s.mv);
    for k in 0..n {
        let o = k * d;
        for i in 0..d {
            s.a[o + i] = sigmoid(w.a0[i] + s.a2_out[o + i]);
        }
    }

    // Key adjustment: kk = normalize(k * k_k per head); k = k * (1 + (a-1)*k_a)
    for k_ in 0..n {
        let o = k_ * d;
        mul_into(&mut s.kk[o..o + d], &s.k[o..o + d], w.k_k);
        normalize_per_head(&mut s.kk[o..o + d], n_heads, hs);
        k_adjust(&mut s.k[o..o + d], &s.a[o..o + d], w.k_a);
    }

    // Value versioning (cross-layer, per lane). Layer 0 seeds each lane's v_first; later
    // layers blend toward it. The v1/v2 matvecs batch across lanes (extra lanes' work is
    // discarded when their v_first is empty — same OUTPUT as the single-lane skip).
    if layer_idx == 0 {
        for k_ in 0..n {
            let o = k_ * d;
            v_firsts[k_].clear();
            v_firsts[k_].extend_from_slice(&s.v[o..o + d]);
        }
    } else {
        grow(&mut s.v1_out, n * lrv);
        grow(&mut s.v2_out, n * d);
        bmatvec_flat(&mut s.v1_out, lrv, w.v1, &s.xv, d, n, &mut s.mv);
        bmatvec_flat(&mut s.v2_out, d, w.v2, &s.v1_out, lrv, n, &mut s.mv);
        for k_ in 0..n {
            if !v_firsts[k_].is_empty() {
                let o = k_ * d;
                for i in 0..d {
                    let vg = sigmoid(w.v0[i] + s.v2_out[o + i]);
                    s.v[o + i] = s.v[o + i] + (v_firsts[k_][i] - s.v[o + i]) * vg;
                }
            }
        }
    }

    // WKV-7 state update + readout (per lane, per head — recurrence is not shareable).
    // kk_a/tmp are the hoisted [hs] temporaries: fully rewritten per head, so
    // reuse across heads/lanes is bit-exact.
    for k_ in 0..n {
        let o = k_ * d;
        let st = &mut states[k_];
        let (kk_l, a_l) = (&s.kk[o..o + d], &s.a[o..o + d]);
        let (v_l, k_l) = (&s.v[o..o + d], &s.k[o..o + d]);
        let (r_l, wd_l) = (&s.r[o..o + d], &s.w_decay[o..o + d]);
        let out_l = &mut s.output[o..o + d];
        for h in 0..n_heads {
            let h_off = h * hs;
            let s_off = h * hs * hs;
            for i in 0..hs {
                s.kk_a[i] = kk_l[h_off + i] * a_l[h_off + i];
            }
            for i in 0..hs {
                let mut sum = 0.0f32;
                for l in 0..hs {
                    sum += st.wkv[s_off + i * hs + l] * -kk_l[h_off + l];
                }
                s.tmp[i] = sum;
            }
            for i in 0..hs {
                let row = s_off + i * hs;
                wkv_row_update(
                    &mut st.wkv[row..row + hs],
                    &wd_l[h_off..h_off + hs],
                    &s.kk_a[..hs],
                    &k_l[h_off..h_off + hs],
                    s.tmp[i],
                    v_l[h_off + i],
                );
            }
            for i in 0..hs {
                let mut sum = 0.0f32;
                for j in 0..hs {
                    sum += st.wkv[s_off + i * hs + j] * r_l[h_off + j];
                }
                out_l[h_off + i] = sum;
            }
        }
        group_norm_in_place(out_l, n_heads, w.ln_gain, w.ln_bias);
        for h in 0..n_heads {
            let h_off = h * hs;
            let mut rk_sum = 0.0f32;
            for i in 0..hs {
                rk_sum += r_l[h_off + i] * k_l[h_off + i] * w.r_k[h_off + i];
            }
            axpy_const(&mut out_l[h_off..h_off + hs], rk_sum, &v_l[h_off..h_off + hs]);
        }
    }

    // Gate: g = sigmoid(xg@g1)@g2 (batched matvecs).
    bmatvec_flat(&mut s.g1_out, gi, w.g1, &s.xg, d, n, &mut s.mv);
    for v_ in &mut s.g1_out[..n * gi] {
        *v_ = sigmoid(*v_);
    }
    bmatvec_flat(&mut s.gate, d, w.g2, &s.g1_out, gi, n, &mut s.mv);
    for k_ in 0..n {
        let o = k_ * d;
        // Split-borrow: output is written, gate is read (disjoint arenas).
        let (out_l, gate_l) = (&mut s.output[o..o + d], &s.gate[o..o + d]);
        mul_assign(out_l, gate_l);
    }

    // Output projection (batched).
    bmatvec_flat(&mut s.out, d, w.o_weight, &s.output, d, n, &mut s.mv);

    // Update shift state (per lane).
    for k_ in 0..n {
        states[k_].shift_x.copy_from_slice(xs[k_]);
    }

    &s.out[..n * d]
}

// ─────────────────────────────────────────────────────────────────────────────
// Channel-mixing (RWKV-7 "Goose": single token-shift, squared-ReLU, NO receptance)
// ─────────────────────────────────────────────────────────────────────────────
//
// RWKV-7 dropped the channel-mix receptance gate present in RWKV-5/6. The HF
// `Rwkv7FeedForward` is just:
//     xk  = x + (shift_x - x) * mix_k
//     out = relu(xk @ Wk)^2 @ Wv
// There is no `ffn_r_weight` / `ffn_mix_r` in the checkpoint (confirmed against
// RWKV7-Goose-World3-2.9B). The earlier RWKV-6 port multiplied by
// `sigmoid(xr @ Wr)`; with `Wr` absent that collapsed to a constant 0.5 gate and
// corrupted every channel-mix output.

struct ChannelMixWeights<'a> {
    mix_k: &'a [f32],
    key_w: Option<&'a ResidentMat>,
    val_w: Option<&'a ResidentMat>,
}

fn channel_mix(
    x: &[f32],
    state: &mut RWKV7LayerState,
    w: &ChannelMixWeights<'_>,
    hidden_dim: usize,
    ffn_inner: usize,
) -> Vec<f32> {
    let mut scratch: Vec<f32> = Vec::new();
    let mut xk = vec![0.0f32; hidden_dim];
    token_shift_mix(&mut xk, x, &state.channel_state, w.mix_k);

    // k = relu(xk @ key_w)^2 (squared ReLU; K4 shared kernel)
    let mut k = vec![0.0f32; ffn_inner];
    matvec_opt(&mut k, w.key_w, &xk, &mut scratch);
    relu_sq(&mut k);

    // out = k @ val_w  (no receptance gate in RWKV-7)
    let mut out = vec![0.0f32; hidden_dim];
    matvec_opt(&mut out, w.val_w, &k, &mut scratch);

    state.channel_state.copy_from_slice(x);
    out
}

/// **Batched channel-mix** over `n` lanes — bit-identical, per lane, to `n` [`channel_mix`]
/// calls; the `key_w`/`val_w` reads are shared across the wave via [`bmatvec_flat`].
/// Intermediates live in the caller's [`ChannelMixBatchScratch`] flat arenas (K2);
/// returns the outputs as `&s.out[..n*d]` (lane k at `[k*d..(k+1)*d]`).
#[allow(dead_code)]
fn channel_mix_batch<'s>(
    xs: &[&[f32]],
    states: &mut [RWKV7LayerState],
    w: &ChannelMixWeights<'_>,
    hidden_dim: usize,
    ffn_inner: usize,
    s: &'s mut ChannelMixBatchScratch,
) -> &'s [f32] {
    let n = xs.len();
    let d = hidden_dim;
    grow(&mut s.xk, n * d);
    grow(&mut s.kbuf, n * ffn_inner);
    grow(&mut s.out, n * d);
    for k_ in 0..n {
        let o = k_ * d;
        token_shift_mix(&mut s.xk[o..o + d], xs[k_], &states[k_].channel_state, w.mix_k);
    }
    // k = relu(xk @ key_w)^2 (batched; K4 shared kernel)
    bmatvec_flat(&mut s.kbuf, ffn_inner, w.key_w, &s.xk, d, n, &mut s.mv);
    relu_sq(&mut s.kbuf[..n * ffn_inner]);
    // out = k @ val_w (batched)
    bmatvec_flat(&mut s.out, d, w.val_w, &s.kbuf, ffn_inner, n, &mut s.mv);
    for k_ in 0..n {
        states[k_].channel_state.copy_from_slice(xs[k_]);
    }
    &s.out[..n * d]
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-layer weights (loaded at construction time)
// ─────────────────────────────────────────────────────────────────────────────

struct RWKV7LayerWeights {
    // LayerNorm for time-mixing
    ln1_w: Vec<f32>,
    ln1_b: Vec<f32>,
    // LayerNorm for channel-mixing
    ln2_w: Vec<f32>,
    ln2_b: Vec<f32>,
    // Time-mixing mix ratios (dense f32)
    mix_r: Vec<f32>,
    mix_w: Vec<f32>,
    mix_k: Vec<f32>,
    mix_v: Vec<f32>,
    mix_a: Vec<f32>,
    mix_g: Vec<f32>,
    // Projection matrices — RESIDENT in source quant (dequant per-row in matvec)
    r_weight: Option<ResidentMat>,
    k_weight: Option<ResidentMat>,
    v_weight: Option<ResidentMat>,
    o_weight: Option<ResidentMat>,
    w0: Vec<f32>,
    w1: Option<ResidentMat>,
    w2: Option<ResidentMat>,
    a0: Vec<f32>,
    a1: Option<ResidentMat>,
    a2: Option<ResidentMat>,
    v0: Vec<f32>,
    v1: Option<ResidentMat>,
    v2: Option<ResidentMat>,
    k_k: Vec<f32>,
    k_a: Vec<f32>,
    r_k: Vec<f32>,
    g1: Option<ResidentMat>,
    g2: Option<ResidentMat>,
    ln_gain: Vec<f32>,
    ln_bias: Vec<f32>,
    // Channel-mixing (RWKV-7: key + value only, no receptance)
    ffn_mix_k: Vec<f32>,
    ffn_k: Option<ResidentMat>,
    ffn_v: Option<ResidentMat>,
}

// ─────────────────────────────────────────────────────────────────────────────
// RWKV7Pipeline
// ─────────────────────────────────────────────────────────────────────────────

pub struct RWKV7Pipeline {
    pub config: RWKV7Config,
    layers: Vec<RWKV7LayerWeights>,
    /// Token embedding [vocab, hidden], RESIDENT in source quant. Used both for
    /// the per-token embedding row lookup AND (when no separate `output_weight`)
    /// as the tied lm_head. `None` in the STREAMING constructor — the host pages
    /// the single embedding row (`stream_embed`) and lm_head shards instead.
    token_embd: Option<ResidentMat>,
    /// Embedding LayerNorm (RWKV "ln0" / Goose `blk_0_pre_norm_*`), applied to
    /// the token embedding once, before block 0. Empty if absent.
    embed_norm_w: Vec<f32>,
    embed_norm_b: Vec<f32>,
    output_norm_w: Vec<f32>,
    output_norm_b: Vec<f32>,
    /// Separate lm_head [vocab, hidden] if present; `None` ⇒ tied to `token_embd`.
    lm_head: Option<ResidentMat>,
    pub states: Vec<RWKV7LayerState>,
    /// Backend retained so `forward_one_streaming` can build each layer's weights
    /// just-in-time and drop them (the JS host pages layer `l`'s tensors in first).
    backend: Arc<dyn WeightBackend>,
    /// Residual + token-shared v_first carried ACROSS the per-layer streaming calls
    /// (`stream_embed` → `stream_layer(l)`×N → `stream_logits`) so the JS host can
    /// page+evict each layer's weights between calls within one token step.
    stream_x: Vec<f32>,
    stream_v_first: Vec<f32>,
    /// Final norm output cached by `stream_logits_begin`, reused across the
    /// vocab-sharded `stream_logits_shard` calls.
    stream_normed: Vec<f32>,
    /// qtype of `token_embd_weight` (for the paged embed-row dequant).
    embd_qtype: QType,
    /// lm_head source tensor (`output_weight`, else tied `token_embd_weight`) + its
    /// qtype — the host pages this tensor in vocab shards for `stream_logits_shard`.
    lm_src_name: String,
    lm_qtype: QType,
}

/// One RWKV-7 block (time-mix + channel-mix) over the running residual `x` and the
/// token-shared `v_first`, advancing this layer's recurrent `state`. Extracted from
/// `forward_one` so the streaming path (which builds `layer` transiently per layer
/// from R2-paged weights, then evicts) runs the IDENTICAL math as the resident path.
fn rwkv7_layer_forward(
    x: &mut [f32],
    v_first: &mut Vec<f32>,
    layer: &RWKV7LayerWeights,
    state: &mut RWKV7LayerState,
    l: usize,
    cfg: &RWKV7Config,
) {
    // A layer = time-mix then channel-mix, each a self-contained residual add.
    // Split so the streaming host can page ONLY one half's weights at a time
    // (peak ≈ max(time-mix, channel-mix) instead of a whole layer) — the path that
    // fits a 2.9B RWKV-7 under a 128MB isolate with room for the recurrent state.
    rwkv7_time_mix_forward(x, v_first, layer, state, l, cfg);
    rwkv7_channel_mix_forward(x, layer, state, cfg);
}

/// Time-mix half: LayerNorm 1 → `time_mix7` → residual add. Reads only the
/// time-mix fields of `layer` (r/k/v/o, w/a/v/g low-rank, mixes, k_k/k_a/r_k,
/// ln_x); the channel-mix (ffn) fields may be absent.
fn rwkv7_time_mix_forward(
    x: &mut [f32],
    v_first: &mut Vec<f32>,
    layer: &RWKV7LayerWeights,
    state: &mut RWKV7LayerState,
    l: usize,
    cfg: &RWKV7Config,
) {
    let d = cfg.hidden_dim;
    // LayerNorm 1 → time-mixing
    let normed = layer_norm(&*x, &layer.ln1_w, &layer.ln1_b);
    let tm_w = TimeMixWeights {
        mix_r: &layer.mix_r,
        mix_w: &layer.mix_w,
        mix_k: &layer.mix_k,
        mix_v: &layer.mix_v,
        mix_a: &layer.mix_a,
        mix_g: &layer.mix_g,
        r_weight: layer.r_weight.as_ref(),
        k_weight: layer.k_weight.as_ref(),
        v_weight: layer.v_weight.as_ref(),
        o_weight: layer.o_weight.as_ref(),
        w0: &layer.w0,
        w1: layer.w1.as_ref(),
        w2: layer.w2.as_ref(),
        a0: &layer.a0,
        a1: layer.a1.as_ref(),
        a2: layer.a2.as_ref(),
        v0: &layer.v0,
        v1: layer.v1.as_ref(),
        v2: layer.v2.as_ref(),
        k_k: &layer.k_k,
        k_a: &layer.k_a,
        r_k: &layer.r_k,
        g1: layer.g1.as_ref(),
        g2: layer.g2.as_ref(),
        ln_gain: &layer.ln_gain,
        ln_bias: &layer.ln_bias,
    };
    let tm_out = time_mix7(&normed, l, state, v_first, &tm_w, cfg);
    add_assign(&mut x[..d], &tm_out);
}

/// Channel-mix half: LayerNorm 2 → `channel_mix` → residual add. Reads only the
/// channel-mix fields of `layer` (ln2, ffn_mix_k, ffn_k/ffn_v); the time-mix
/// fields may be absent.
fn rwkv7_channel_mix_forward(
    x: &mut [f32],
    layer: &RWKV7LayerWeights,
    state: &mut RWKV7LayerState,
    cfg: &RWKV7Config,
) {
    let d = cfg.hidden_dim;
    let normed2 = layer_norm(&*x, &layer.ln2_w, &layer.ln2_b);
    let cm_w = ChannelMixWeights {
        mix_k: &layer.ffn_mix_k,
        key_w: layer.ffn_k.as_ref(),
        val_w: layer.ffn_v.as_ref(),
    };
    let cm_out = channel_mix(&normed2, state, &cm_w, d, cfg.ffn_inner);
    add_assign(&mut x[..d], &cm_out);
}

/// Batched twin of [`rwkv7_time_mix_forward`] — LN1 (per lane) → [`time_mix7_batch`]
/// (shared weight reads) → residual add (per lane). The `TimeMixWeights` view is built
/// ONCE for the layer and shared across the whole wave.
#[allow(dead_code)]
fn rwkv7_time_mix_forward_batch(
    xs: &mut [Vec<f32>],
    v_firsts: &mut [Vec<f32>],
    layer: &RWKV7LayerWeights,
    states: &mut [RWKV7LayerState],
    l: usize,
    cfg: &RWKV7Config,
) {
    // Width-1 wave: dispatch to the SOLO half. At n==1 the batch path is bit-identical
    // to solo (per the rwkv7_batched_* parity gates) but pays Vec-of-Vec allocation and
    // ref-collect churn on every call — the measured ~1.3× width-1 gap vs the solo
    // stream path. The solo half runs the flat-buffer code directly.
    if xs.len() == 1 {
        rwkv7_time_mix_forward(&mut xs[0], &mut v_firsts[0], layer, &mut states[0], l, cfg);
        return;
    }
    let d = cfg.hidden_dim;
    let n = xs.len();
    let tm_w = TimeMixWeights {
        mix_r: &layer.mix_r,
        mix_w: &layer.mix_w,
        mix_k: &layer.mix_k,
        mix_v: &layer.mix_v,
        mix_a: &layer.mix_a,
        mix_g: &layer.mix_g,
        r_weight: layer.r_weight.as_ref(),
        k_weight: layer.k_weight.as_ref(),
        v_weight: layer.v_weight.as_ref(),
        o_weight: layer.o_weight.as_ref(),
        w0: &layer.w0,
        w1: layer.w1.as_ref(),
        w2: layer.w2.as_ref(),
        a0: &layer.a0,
        a1: layer.a1.as_ref(),
        a2: layer.a2.as_ref(),
        v0: &layer.v0,
        v1: layer.v1.as_ref(),
        v2: layer.v2.as_ref(),
        k_k: &layer.k_k,
        k_a: &layer.k_a,
        r_k: &layer.r_k,
        g1: layer.g1.as_ref(),
        g2: layer.g2.as_ref(),
        ln_gain: &layer.ln_gain,
        ln_bias: &layer.ln_bias,
    };
    // K2: per-lane LN into the shared flat arena + stack view table — the old
    // per-call `Vec<Vec<f32>>` collect + `Vec<&[f32]>` ref collect are gone.
    BATCH_SCRATCH.with(|cell| {
        let sc = &mut *cell.borrow_mut();
        grow(&mut sc.normed, n * d);
        for (k, x) in xs.iter().enumerate() {
            layer_norm_into(x, &layer.ln1_w, &layer.ln1_b, &mut sc.normed[k * d..(k + 1) * d]);
        }
        let BatchScratch { normed, tm, .. } = sc;
        let mut view_store: [&[f32]; MAX_WAVE_LANES] = [&[]; MAX_WAVE_LANES];
        let heap_views: Vec<&[f32]>;
        let views: &[&[f32]] = if n <= MAX_WAVE_LANES {
            for (k, slot) in view_store.iter_mut().enumerate().take(n) {
                *slot = &normed[k * d..(k + 1) * d];
            }
            &view_store[..n]
        } else {
            heap_views = (0..n).map(|k| &normed[k * d..(k + 1) * d]).collect();
            &heap_views
        };
        let tm_out = time_mix7_batch(views, l, states, v_firsts, &tm_w, cfg, tm);
        for k in 0..n {
            let o = k * d;
            add_assign(&mut xs[k][..d], &tm_out[o..o + d]);
        }
    });
}

/// Batched twin of [`rwkv7_channel_mix_forward`].
#[allow(dead_code)]
fn rwkv7_channel_mix_forward_batch(
    xs: &mut [Vec<f32>],
    layer: &RWKV7LayerWeights,
    states: &mut [RWKV7LayerState],
    cfg: &RWKV7Config,
) {
    // Width-1 wave: solo half directly (see rwkv7_time_mix_forward_batch).
    if xs.len() == 1 {
        rwkv7_channel_mix_forward(&mut xs[0], layer, &mut states[0], cfg);
        return;
    }
    let d = cfg.hidden_dim;
    let n = xs.len();
    let cm_w = ChannelMixWeights {
        mix_k: &layer.ffn_mix_k,
        key_w: layer.ffn_k.as_ref(),
        val_w: layer.ffn_v.as_ref(),
    };
    // K2: flat LN arena + stack view table (see rwkv7_time_mix_forward_batch).
    BATCH_SCRATCH.with(|cell| {
        let sc = &mut *cell.borrow_mut();
        grow(&mut sc.normed, n * d);
        for (k, x) in xs.iter().enumerate() {
            layer_norm_into(x, &layer.ln2_w, &layer.ln2_b, &mut sc.normed[k * d..(k + 1) * d]);
        }
        let BatchScratch { normed, cm, .. } = sc;
        let mut view_store: [&[f32]; MAX_WAVE_LANES] = [&[]; MAX_WAVE_LANES];
        let heap_views: Vec<&[f32]>;
        let views: &[&[f32]] = if n <= MAX_WAVE_LANES {
            for (k, slot) in view_store.iter_mut().enumerate().take(n) {
                *slot = &normed[k * d..(k + 1) * d];
            }
            &view_store[..n]
        } else {
            heap_views = (0..n).map(|k| &normed[k * d..(k + 1) * d]).collect();
            &heap_views
        };
        let cm_out = channel_mix_batch(views, states, &cm_w, d, cfg.ffn_inner, cm);
        for k in 0..n {
            let o = k * d;
            add_assign(&mut xs[k][..d], &cm_out[o..o + d]);
        }
    });
}

/// Build ONE layer's weights from the backend — the same per-layer construction
/// `from_knot` does inline. Used by `forward_one_streaming` to page a layer in,
/// run it, and drop it (so peak memory is ~one layer, not all N). Parity with the
/// resident path is enforced by the `forward_one_streaming == forward_one` test.
/// Which half's big tensors to build. The cheap per-layer vectors (norms/mixes)
/// are always built; only the big projection/ffn matrices are gated, so the
/// streaming host pages just one half into the backend at a time.
#[derive(Clone, Copy, PartialEq, Eq)]
enum LayerPart {
    All,
    TimeMix,
    ChannelMix,
}

fn build_layer_weights(backend: &dyn WeightBackend, l: usize, cfg: &RWKV7Config) -> RWKV7LayerWeights {
    build_layer_weights_part(backend, l, cfg, LayerPart::All)
}

fn build_layer_weights_part(
    backend: &dyn WeightBackend,
    l: usize,
    cfg: &RWKV7Config,
    part: LayerPart,
) -> RWKV7LayerWeights {
    let d = cfg.hidden_dim;
    let lrw = cfg.low_rank_w;
    let lra = cfg.low_rank_a;
    let lrv = cfg.low_rank_v;
    let gi = cfg.gate_inner;
    let fi = cfg.ffn_inner;
    let n = |s: &str| format!("blk_{l}_{s}");
    let fetch_first = |names: &[&str], n_elems: usize| -> Vec<f32> {
        for nm in names {
            if backend.has_tensor(nm) {
                return fetch_auto(backend, nm, n_elems);
            }
        }
        vec![0.0; n_elems]
    };
    // Big-matrix builders, gated by `part` so only one half is resident at a time.
    // LAZY: the thunk (and thus the backend fetch) runs ONLY when the half is
    // wanted — otherwise the other half's (unpaged) bytes would be fetched and the
    // kernel would fault. The cheap vectors below are always built (paged in both
    // halves by the host).
    let want_tm = part != LayerPart::ChannelMix;
    let want_cm = part != LayerPart::TimeMix;
    let tm = |f: &dyn Fn() -> Option<ResidentMat>| if want_tm { f() } else { None };
    let cm = |f: &dyn Fn() -> Option<ResidentMat>| if want_cm { f() } else { None };
    RWKV7LayerWeights {
        ln1_w: fetch_first(&[&n("attn_norm_weight"), &n("ln1_weight")], d),
        ln1_b: fetch_first(&[&n("attn_norm_bias"), &n("ln1_bias")], d),
        ln2_w: fetch_first(&[&n("ffn_norm_weight"), &n("ln2_weight")], d),
        ln2_b: fetch_first(&[&n("ffn_norm_bias"), &n("ln2_bias")], d),
        mix_r: fetch_or_zeros(backend, &n("rwkv_mix_r"), d),
        mix_w: fetch_or_zeros(backend, &n("rwkv_mix_w"), d),
        mix_k: fetch_or_zeros(backend, &n("rwkv_mix_k"), d),
        mix_v: fetch_or_zeros(backend, &n("rwkv_mix_v"), d),
        mix_a: fetch_or_zeros(backend, &n("rwkv_mix_a"), d),
        mix_g: fetch_or_zeros(backend, &n("rwkv_mix_g"), d),
        r_weight: tm(&|| resident_opt(backend, &n("rwkv_r_weight"), d, d)),
        k_weight: tm(&|| resident_opt(backend, &n("rwkv_k_weight"), d, d)),
        v_weight: tm(&|| resident_opt(backend, &n("rwkv_v_weight"), d, d)),
        o_weight: tm(&|| resident_opt(backend, &n("rwkv_o_weight"), d, d)),
        w0: fetch_first(&[&n("rwkv_w0"), &n("rwkv_w2_bias")], d),
        w1: tm(&|| resident_opt(backend, &n("rwkv_w1"), lrw, d)),
        w2: tm(&|| resident_opt(backend, &n("rwkv_w2"), d, lrw)),
        a0: fetch_first(&[&n("rwkv_a0"), &n("rwkv_a2_bias")], d),
        a1: tm(&|| resident_opt(backend, &n("rwkv_a1"), lra, d)),
        a2: tm(&|| resident_opt(backend, &n("rwkv_a2"), d, lra)),
        v0: fetch_first(&[&n("rwkv_v0"), &n("rwkv_v_lora2_bias")], d),
        v1: tm(&|| resident_first(backend, &[&n("rwkv_v1"), &n("rwkv_v_lora1")], lrv, d)),
        v2: tm(&|| resident_first(backend, &[&n("rwkv_v2"), &n("rwkv_v_lora2")], d, lrv)),
        k_k: fetch_or_zeros(backend, &n("rwkv_k_k"), d),
        k_a: fetch_or_zeros(backend, &n("rwkv_k_a"), d),
        r_k: fetch_or_zeros(backend, &n("rwkv_r_k"), d),
        g1: tm(&|| resident_first(backend, &[&n("rwkv_g1"), &n("rwkv_g1_weight")], gi, d)),
        g2: tm(&|| resident_first(backend, &[&n("rwkv_g2"), &n("rwkv_g2_weight")], d, gi)),
        ln_gain: fetch_or_zeros(backend, &n("rwkv_ln_x_weight"), d),
        ln_bias: fetch_or_zeros(backend, &n("rwkv_ln_x_bias"), d),
        ffn_mix_k: fetch_or_zeros(backend, &n("ffn_mix_k"), d),
        ffn_k: cm(&|| resident_opt(backend, &n("ffn_k_weight"), fi, d)),
        ffn_v: cm(&|| resident_opt(backend, &n("ffn_v_weight"), d, fi)),
    }
}

/// Resolve the embed/lm_head qtypes + the lm_head source tensor name (separate
/// `output_weight`, else tied `token_embd_weight`). Used by both constructors so
/// the streaming path knows how to dequant the paged embed row + lm_head shards.
fn resolve_lm_meta(backend: &dyn WeightBackend) -> (QType, String, QType) {
    let embd_qtype = backend
        .tensor_info("token_embd_weight")
        .map(|i| resolve_qtype(&i.tensor_type))
        .unwrap_or(QType::F32);
    if backend.has_tensor("output_weight") {
        let q = backend
            .tensor_info("output_weight")
            .map(|i| resolve_qtype(&i.tensor_type))
            .unwrap_or(QType::F32);
        (embd_qtype, "output_weight".to_string(), q)
    } else {
        (embd_qtype, "token_embd_weight".to_string(), embd_qtype)
    }
}

impl RWKV7Pipeline {
    pub fn from_knot(knot_cfg: &KnotConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let mut cfg = RWKV7Config::from_knot(knot_cfg);
        let d = cfg.hidden_dim;

        // The config block's low-rank / gate-inner values are unreliable for the
        // RWKV7-Goose knots (they were defaulted, not read from the checkpoint).
        // Derive the true inner dims from the layer-0 tensor byte lengths so the
        // mat_vec calls index the right number of elements:
        //   w1: [low_rank_w, d]  -> n_elems / d = low_rank_w
        //   a1: [low_rank_a, d]  -> n_elems / d = low_rank_a
        //   v_lora1: [low_rank_v, d] -> n_elems / d = low_rank_v
        //   g1: [gate_inner, d]  -> n_elems / d = gate_inner
        if let Some(n) = tensor_n_elems(&*backend, "blk_0_rwkv_w1") {
            cfg.low_rank_w = (n / d).max(1);
        }
        if let Some(n) = tensor_n_elems(&*backend, "blk_0_rwkv_a1") {
            cfg.low_rank_a = (n / d).max(1);
        }
        // v-lora lives on layers 1+; probe layer 1.
        if let Some(n) = tensor_n_elems(&*backend, "blk_1_rwkv_v_lora1")
            .or_else(|| tensor_n_elems(&*backend, "blk_1_rwkv_v1"))
        {
            cfg.low_rank_v = (n / d).max(1);
        }
        if let Some(n) = tensor_n_elems(&*backend, "blk_0_rwkv_g1") {
            cfg.gate_inner = (n / d).max(1);
        }
        let lrw = cfg.low_rank_w;
        let lra = cfg.low_rank_a;
        let lrv = cfg.low_rank_v;
        let gi = cfg.gate_inner;
        let fi = cfg.ffn_inner;

        let token_embd =
            ResidentMat::from_backend(&*backend, "token_embd_weight", cfg.vocab_size, d);
        // Embedding LayerNorm (ln0). Goose ships it as `blk_0_pre_norm_*`.
        let embed_norm_w = if backend.has_tensor("blk_0_pre_norm_weight") {
            fetch_f32(&*backend, "blk_0_pre_norm_weight")
        } else {
            fetch_or_zeros(&*backend, "embed_norm_weight", 0)
        };
        let embed_norm_b = if backend.has_tensor("blk_0_pre_norm_bias") {
            fetch_f32(&*backend, "blk_0_pre_norm_bias")
        } else {
            fetch_or_zeros(&*backend, "embed_norm_bias", 0)
        };
        let output_norm_w = fetch_or_zeros(&*backend, "output_norm_weight", d);
        let output_norm_b = fetch_or_zeros(&*backend, "output_norm_bias", d);
        // Tied-embedding fallback: when the knot has no separate output
        // projection (many SSM/RWKV models tie lm_head to the input embedding),
        // `None` here means `forward_one` reuses `token_embd` as the (tied)
        // lm_head — no f32 clone of the ~180 MB embedding table.
        let lm_head = resident_opt(&*backend, "output_weight", cfg.vocab_size, d);

        let (embd_qtype, lm_src_name, lm_qtype) = resolve_lm_meta(&*backend);

        let mut layers = Vec::with_capacity(cfg.num_layers);
        let mut states = Vec::with_capacity(cfg.num_layers);

        for l in 0..cfg.num_layers {
            let n = |s: &str| format!("blk_{l}_{s}");
            // `fetch_first`: take the first present name from a list of aliases,
            // else zero-fill. Lets us support both the Goose checkpoint names
            // (attn_norm / ffn_norm / *2_bias / v_lora*) and the older
            // ln1/ln2 / w0 / v0..v2 naming without a second code path.
            let fetch_first = |names: &[&str], n_elems: usize| -> Vec<f32> {
                for nm in names {
                    if backend.has_tensor(nm) {
                        return fetch_auto(&*backend, nm, n_elems);
                    }
                }
                vec![0.0; n_elems]
            };

            // Block LayerNorms.
            //   ln1 (pre-time-mix)    = Goose `attn_norm`  (alias `ln1`)
            //   ln2 (pre-channel-mix) = Goose `ffn_norm`   (alias `ln2`)
            let ln1_w = fetch_first(&[&n("attn_norm_weight"), &n("ln1_weight")], d);
            let ln1_b = fetch_first(&[&n("attn_norm_bias"), &n("ln1_bias")], d);
            let ln2_w = fetch_first(&[&n("ffn_norm_weight"), &n("ln2_weight")], d);
            let ln2_b = fetch_first(&[&n("ffn_norm_bias"), &n("ln2_bias")], d);

            layers.push(RWKV7LayerWeights {
                ln1_w,
                ln1_b,
                ln2_w,
                ln2_b,

                // Time-mixing mix ratios
                mix_r: fetch_or_zeros(&*backend, &n("rwkv_mix_r"), d),
                mix_w: fetch_or_zeros(&*backend, &n("rwkv_mix_w"), d),
                mix_k: fetch_or_zeros(&*backend, &n("rwkv_mix_k"), d),
                mix_v: fetch_or_zeros(&*backend, &n("rwkv_mix_v"), d),
                mix_a: fetch_or_zeros(&*backend, &n("rwkv_mix_a"), d),
                mix_g: fetch_or_zeros(&*backend, &n("rwkv_mix_g"), d),

                // Main projections (resident: rows=out dim, cols=in dim)
                r_weight: resident_opt(&*backend, &n("rwkv_r_weight"), d, d),
                k_weight: resident_opt(&*backend, &n("rwkv_k_weight"), d, d),
                v_weight: resident_opt(&*backend, &n("rwkv_v_weight"), d, d),
                o_weight: resident_opt(&*backend, &n("rwkv_o_weight"), d, d),

                // Dynamic decay. Goose folds the additive bias `w0` into the
                // lora's second-matrix bias `w2_bias`; older encodes wrote `w0`.
                w0: fetch_first(&[&n("rwkv_w0"), &n("rwkv_w2_bias")], d),
                w1: resident_opt(&*backend, &n("rwkv_w1"), lrw, d),
                w2: resident_opt(&*backend, &n("rwkv_w2"), d, lrw),

                // Dynamic attention. `a0` == Goose `a2_bias`.
                a0: fetch_first(&[&n("rwkv_a0"), &n("rwkv_a2_bias")], d),
                a1: resident_opt(&*backend, &n("rwkv_a1"), lra, d),
                a2: resident_opt(&*backend, &n("rwkv_a2"), d, lra),

                // Value versioning (layers 1+). `v0` == Goose `v_lora2_bias`,
                // `v1/v2` == Goose `v_lora1/v_lora2`.
                v0: fetch_first(&[&n("rwkv_v0"), &n("rwkv_v_lora2_bias")], d),
                v1: resident_first(&*backend, &[&n("rwkv_v1"), &n("rwkv_v_lora1")], lrv, d),
                v2: resident_first(&*backend, &[&n("rwkv_v2"), &n("rwkv_v_lora2")], d, lrv),

                // Key adjustment
                k_k: fetch_or_zeros(&*backend, &n("rwkv_k_k"), d),
                k_a: fetch_or_zeros(&*backend, &n("rwkv_k_a"), d),
                r_k: fetch_or_zeros(&*backend, &n("rwkv_r_k"), d),

                // Gate (Goose: `rwkv_g1` / `rwkv_g2`; older: `*_weight`)
                g1: resident_first(&*backend, &[&n("rwkv_g1"), &n("rwkv_g1_weight")], gi, d),
                g2: resident_first(&*backend, &[&n("rwkv_g2"), &n("rwkv_g2_weight")], d, gi),

                // Group norm (ln_x / g_norm)
                ln_gain: fetch_or_zeros(&*backend, &n("rwkv_ln_x_weight"), d),
                ln_bias: fetch_or_zeros(&*backend, &n("rwkv_ln_x_bias"), d),

                // Channel-mixing (key + value only — no receptance in RWKV-7)
                ffn_mix_k: fetch_or_zeros(&*backend, &n("ffn_mix_k"), d),
                ffn_k: resident_opt(&*backend, &n("ffn_k_weight"), fi, d),
                ffn_v: resident_opt(&*backend, &n("ffn_v_weight"), d, fi),
            });
            states.push(RWKV7LayerState::new(d, cfg.n_heads, cfg.head_size));
        }

        Self {
            config: cfg,
            layers,
            token_embd: Some(token_embd),
            embed_norm_w,
            embed_norm_b,
            output_norm_w,
            output_norm_b,
            lm_head,
            states,
            backend,
            stream_x: Vec::new(),
            stream_v_first: Vec::new(),
            stream_normed: Vec::new(),
            embd_qtype,
            lm_src_name,
            lm_qtype,
        }
    }

    /// Streaming constructor — builds ONLY the small resident state (LayerNorms +
    /// O(1) recurrent states) and the metadata for the paged embed/lm_head. The
    /// per-layer weights, the embedding table, and the lm_head are NOT made
    /// resident (that 3.2GB+ is what OOMs a 128MB isolate); the host pages each
    /// layer (`stream_layer`), the embedding row (`stream_embed`), and the lm_head
    /// shards (`stream_logits_shard`) on demand. The layer-0/1 RWKV tensors must be
    /// present at construction for the low-rank dim derivation (the host pages them
    /// in, then may evict). `forward_one`/`stream_logits` (resident lm_head) are
    /// NOT valid on a streaming pipeline — drive it via stream_embed/stream_layer/
    /// stream_logits_begin/stream_logits_shard.
    pub fn from_knot_streaming(knot_cfg: &KnotConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let mut cfg = RWKV7Config::from_knot(knot_cfg);
        let d = cfg.hidden_dim;
        if let Some(n) = tensor_n_elems(&*backend, "blk_0_rwkv_w1") {
            cfg.low_rank_w = (n / d).max(1);
        }
        if let Some(n) = tensor_n_elems(&*backend, "blk_0_rwkv_a1") {
            cfg.low_rank_a = (n / d).max(1);
        }
        if let Some(n) = tensor_n_elems(&*backend, "blk_1_rwkv_v_lora1")
            .or_else(|| tensor_n_elems(&*backend, "blk_1_rwkv_v1"))
        {
            cfg.low_rank_v = (n / d).max(1);
        }
        if let Some(n) = tensor_n_elems(&*backend, "blk_0_rwkv_g1") {
            cfg.gate_inner = (n / d).max(1);
        }

        let embed_norm_w = if backend.has_tensor("blk_0_pre_norm_weight") {
            fetch_f32(&*backend, "blk_0_pre_norm_weight")
        } else {
            fetch_or_zeros(&*backend, "embed_norm_weight", 0)
        };
        let embed_norm_b = if backend.has_tensor("blk_0_pre_norm_bias") {
            fetch_f32(&*backend, "blk_0_pre_norm_bias")
        } else {
            fetch_or_zeros(&*backend, "embed_norm_bias", 0)
        };
        let output_norm_w = fetch_or_zeros(&*backend, "output_norm_weight", d);
        let output_norm_b = fetch_or_zeros(&*backend, "output_norm_bias", d);
        let (embd_qtype, lm_src_name, lm_qtype) = resolve_lm_meta(&*backend);

        let mut states = Vec::with_capacity(cfg.num_layers);
        for _ in 0..cfg.num_layers {
            states.push(RWKV7LayerState::new(d, cfg.n_heads, cfg.head_size));
        }

        Self {
            config: cfg,
            layers: Vec::new(),
            token_embd: None,
            embed_norm_w,
            embed_norm_b,
            output_norm_w,
            output_norm_b,
            lm_head: None,
            states,
            backend,
            stream_x: Vec::new(),
            stream_v_first: Vec::new(),
            stream_normed: Vec::new(),
            embd_qtype,
            lm_src_name,
            lm_qtype,
        }
    }

    pub fn reset_states(&mut self) {
        for s in &mut self.states {
            s.reset();
        }
    }

    /// Forward one token, return raw logits [vocab_size].
    pub fn forward_one(&mut self, token_id: u32, logits: &mut [f32]) {
        let cfg = &self.config;
        let tok = token_id as usize;
        let d = cfg.hidden_dim;

        // Embed: dequantize row `tok` of the resident embedding table.
        let mut x = vec![0.0f32; d];
        self.token_embd
            .as_ref()
            .expect("forward_one needs a resident token_embd (streaming pipe? use stream_embed)")
            .dequant_row_into(tok, &mut x);

        // Embedding LayerNorm (RWKV ln0 / Goose pre_norm), once before block 0.
        if !self.embed_norm_w.is_empty() {
            x = layer_norm(&x, &self.embed_norm_w, &self.embed_norm_b);
        }

        // v_first shared across all layers in this token step (seeded by layer 0).
        let mut v_first: Vec<f32> = Vec::new();

        for l in 0..cfg.num_layers {
            // Extracted so the streaming path (per-layer weights paged from R2 and
            // evicted) runs the identical math as the resident path.
            rwkv7_layer_forward(&mut x, &mut v_first, &self.layers[l], &mut self.states[l], l, cfg);
        }

        // Final layer norm
        let normed_out = layer_norm(&x, &self.output_norm_w, &self.output_norm_b);

        // lm_head — separate `output_weight` if present, else tied to the
        // resident token embedding. Dequantized per-row inside the matvec.
        assert_eq!(logits.len(), cfg.vocab_size);
        let lm_w = self.resident_lm_w();
        let mut scratch: Vec<f32> = Vec::new();
        matvec_resident(logits, lm_w, &normed_out, &mut scratch);
    }

    /// FOIL / low-rank capture hook: byte-for-byte the same math as
    /// [`forward_one`], but ALSO returns the final-LayerNorm hidden state
    /// (`normed_out`, length `hidden_dim`) — the exact activation the lm_head
    /// decode dot descends against. Used to measure the effective rank of a REAL
    /// activation (participation ratio / 90%-energy dims) and the winning-token
    /// cosine alignment (see the `foil-rank-probe` bin).
    pub fn forward_one_capture(&mut self, token_id: u32, logits: &mut [f32]) -> Vec<f32> {
        let cfg = &self.config;
        let tok = token_id as usize;
        let d = cfg.hidden_dim;

        let mut x = vec![0.0f32; d];
        self.token_embd
            .as_ref()
            .expect("forward_one_capture needs a resident token_embd")
            .dequant_row_into(tok, &mut x);
        if !self.embed_norm_w.is_empty() {
            x = layer_norm(&x, &self.embed_norm_w, &self.embed_norm_b);
        }

        let mut v_first: Vec<f32> = Vec::new();
        for l in 0..cfg.num_layers {
            rwkv7_layer_forward(&mut x, &mut v_first, &self.layers[l], &mut self.states[l], l, cfg);
        }

        let normed_out = layer_norm(&x, &self.output_norm_w, &self.output_norm_b);
        assert_eq!(logits.len(), cfg.vocab_size);
        let lm_w = self.resident_lm_w();
        let mut scratch: Vec<f32> = Vec::new();
        matvec_resident(logits, lm_w, &normed_out, &mut scratch);
        normed_out
    }

    /// Dequantize a single lm_head row (length `hidden_dim`) — the weight row the
    /// decode dot multiplies for a given output token. For winning-token cosine
    /// alignment against a captured hidden state.
    pub fn lm_head_row(&self, row: usize) -> Vec<f32> {
        let lm_w = self.resident_lm_w();
        let mut out = vec![0.0f32; self.config.hidden_dim];
        lm_w.dequant_row_into(row, &mut out);
        out
    }

    /// Fresh per-lane recurrent state for an `n`-lane batched forward, laid out
    /// `[layer][lane]` so a layer's lanes are contiguous for [`time_mix7_batch`].
    pub fn new_batch_states(&self, n: usize) -> Vec<Vec<RWKV7LayerState>> {
        let cfg = &self.config;
        (0..cfg.num_layers)
            .map(|_| {
                (0..n)
                    .map(|_| RWKV7LayerState::new(cfg.hidden_dim, cfg.n_heads, cfg.head_size))
                    .collect()
            })
            .collect()
    }

    /// Like [`new_batch_states`](Self::new_batch_states) but allocates lane state ONLY for
    /// layers `[a, b)` — a fleet STATION's resident range — so it never pays memory for
    /// layers it doesn't hold (an 8-layer station of a 24-layer model allocates 8, not 24).
    /// Layers outside the range get an empty `Vec` (no recurrent state).
    pub fn new_batch_states_range(&self, n: usize, a: usize, b: usize) -> Vec<Vec<RWKV7LayerState>> {
        let cfg = &self.config;
        (0..cfg.num_layers)
            .map(|l| {
                if l >= a && l < b {
                    (0..n)
                        .map(|_| RWKV7LayerState::new(cfg.hidden_dim, cfg.n_heads, cfg.head_size))
                        .collect()
                } else {
                    Vec::new()
                }
            })
            .collect()
    }

    // ── Lane lifecycle (continuous batching) ─────────────────────────────────
    // A live wave gains and loses lanes between tokens (continuous batching). These
    // helpers mutate the CALLER-owned `[layer][lane]` state (the same external-state
    // contract as `stream_layer_timemix_batch`), so they are natively testable and
    // the wasm bindings just delegate. A lane's slot is always created, moved, or
    // zeroed WHOLE — no other lane's state is ever touched, which is what keeps the
    // batch-isolation license intact (`Gnosis.VGpuWarp.batch_isolation`: a lane's
    // result depends only on its own input/state).

    /// Append ONE fresh zero-state lane for layers `[a, b)` to a caller-owned batch:
    /// `xs`/`vfs` gain an empty slot, each in-range layer gains a zero
    /// [`RWKV7LayerState`]. Returns the new lane's index. Existing lanes' state is
    /// untouched (`Gnosis.VGpuWarp.batch_isolation`).
    pub fn batch_add_lane(
        &self,
        xs: &mut Vec<Vec<f32>>,
        vfs: &mut Vec<Vec<f32>>,
        states: &mut [Vec<RWKV7LayerState>],
        a: usize,
        b: usize,
    ) -> usize {
        let cfg = &self.config;
        let lane = xs.len();
        xs.push(Vec::new());
        vfs.push(Vec::new());
        for l in a..b {
            states[l].push(RWKV7LayerState::new(cfg.hidden_dim, cfg.n_heads, cfg.head_size));
        }
        lane
    }

    /// Remove lane `lane` from a caller-owned batch via `swap_remove` on every vec
    /// (O(1), order-NOT-preserving: the last lane moves into the vacated slot).
    /// Returns the OLD index of the lane that moved in (== `lane` when it was
    /// already last) so the host can re-point its session→lane map. Only the two
    /// slots involved change; every other lane's state is untouched.
    pub fn batch_remove_lane(
        xs: &mut Vec<Vec<f32>>,
        vfs: &mut Vec<Vec<f32>>,
        states: &mut [Vec<RWKV7LayerState>],
        lane: usize,
    ) -> usize {
        let moved_from = xs.len() - 1;
        xs.swap_remove(lane);
        vfs.swap_remove(lane);
        for per_layer in states.iter_mut() {
            // Layers outside the station's range hold no lane state (empty Vec).
            if !per_layer.is_empty() {
                per_layer.swap_remove(lane);
            }
        }
        moved_from
    }

    /// Zero lane `lane`'s recurrent state over layers `[a, b)` — a fresh sequence
    /// joining the wave mid-flight reuses the slot without reallocating.
    pub fn batch_reset_lane(states: &mut [Vec<RWKV7LayerState>], lane: usize, a: usize, b: usize) {
        for l in a..b {
            states[l][lane].reset();
        }
    }

    /// **Batched resident forward** — advances `n = tokens.len()` independent lanes one
    /// token each, sharing the resident weights so each weight row is paged/dequantized
    /// ONCE per step for the whole wave (the width-axis amortization). `lane_states` is
    /// `[layer][lane]` (see [`new_batch_states`](Self::new_batch_states)); `logits_out[lane]`
    /// receives each lane's logits. `&self` (not `&mut`): the recurrent state lives in
    /// `lane_states`, so the call is re-entrant. Bit-identical, per lane, to `n`
    /// [`forward_one`](Self::forward_one) calls — gated by `rwkv7_batched_forward_parity`.
    pub fn forward_one_batch(
        &self,
        tokens: &[u32],
        lane_states: &mut [Vec<RWKV7LayerState>],
        logits_out: &mut [Vec<f32>],
    ) {
        let cfg = &self.config;
        let d = cfg.hidden_dim;
        let n = tokens.len();
        assert_eq!(logits_out.len(), n);
        assert_eq!(lane_states.len(), cfg.num_layers);

        // Embed each lane (+ optional embedding LayerNorm), per lane.
        let embd = self
            .token_embd
            .as_ref()
            .expect("forward_one_batch needs a resident token_embd");
        let mut xs: Vec<Vec<f32>> = vec![vec![0.0f32; d]; n];
        for k in 0..n {
            embd.dequant_row_into(tokens[k] as usize, &mut xs[k]);
            if !self.embed_norm_w.is_empty() {
                xs[k] = layer_norm(&xs[k], &self.embed_norm_w, &self.embed_norm_b);
            }
        }

        // v_first per lane, shared across layers in this step (seeded by layer 0).
        let mut v_firsts: Vec<Vec<f32>> = vec![Vec::new(); n];
        for l in 0..cfg.num_layers {
            rwkv7_time_mix_forward_batch(&mut xs, &mut v_firsts, &self.layers[l], &mut lane_states[l], l, cfg);
            rwkv7_channel_mix_forward_batch(&mut xs, &self.layers[l], &mut lane_states[l], cfg);
        }

        // Final LayerNorm (per lane) → lm_head (batched: one weight read per row, all lanes).
        let normed: Vec<Vec<f32>> = xs
            .iter()
            .map(|x| layer_norm(x, &self.output_norm_w, &self.output_norm_b))
            .collect();
        for lo in logits_out.iter_mut() {
            assert_eq!(lo.len(), cfg.vocab_size);
        }
        let lm_w = self.resident_lm_w();
        let mut scratch: Vec<f32> = Vec::new();
        bmatvec(logits_out, Some(lm_w), &normed, &mut scratch);
    }

    /// Streaming forward: builds each layer's big weights from the backend
    /// just-in-time and drops them after the layer, so peak memory is ~ONE layer
    /// (not all N) — the path that fits a 2.9B RWKV-7 in a 128 MB isolate. The JS
    /// host pages layer `l`'s tensors into the backend before this runs. The math
    /// is IDENTICAL to `forward_one` (same `rwkv7_layer_forward`); the
    /// `forward_one_streaming == forward_one` test enforces it. (Embedding row +
    /// lm_head still read here from resident bits; streaming those is the next
    /// memory step — the per-layer weights are the bulk.)
    pub fn forward_one_streaming(&mut self, token_id: u32, logits: &mut [f32]) {
        self.stream_embed(token_id);
        for l in 0..self.config.num_layers {
            // Use the split halves so this driver — and the parity test that gates
            // it against forward_one — also validates the sub-layer streaming path.
            self.stream_layer_timemix(l);
            self.stream_layer_channelmix(l);
        }
        self.stream_logits(logits);
    }

    // ── Per-layer streaming API (JS-drivable) ────────────────────────────────
    // The isolate host runs one token as: `stream_embed(token)` →
    // `stream_layer(l)` for l in 0..N (paging layer l's tensors into the backend
    // just before each call and evicting after) → `stream_logits(out)`. The
    // residual + v_first live on the pipeline (`stream_x` / `stream_v_first`)
    // across these calls. forward_one_streaming above is the all-resident driver.

    /// Begin a token: embed its row into the carried residual `stream_x`.
    pub fn stream_embed(&mut self, token_id: u32) {
        let d = self.config.hidden_dim;
        let mut x = vec![0.0f32; d];
        match &self.token_embd {
            // Resident table (all-in-memory path).
            Some(embd) => embd.dequant_row_into(token_id as usize, &mut x),
            // Streaming: the host paged THIS token's embedding row in as the
            // tensor `token_embd_row` (a single [1, hidden] row in source quant).
            None => {
                let bytes = self
                    .backend
                    .fetch_tensor("token_embd_row")
                    .expect("stream_embed (paged): host must set 'token_embd_row'");
                ResidentMat::from_parts(bytes, self.embd_qtype, 1, d).dequant_row_into(0, &mut x);
            }
        }
        if !self.embed_norm_w.is_empty() {
            x = layer_norm(&x, &self.embed_norm_w, &self.embed_norm_b);
        }
        self.stream_x = x;
        self.stream_v_first = Vec::new();
    }

    /// Advance ONE layer: build its weights from the backend (the host paged them
    /// in), run the block on `stream_x`, advance `states[l]`, then drop the
    /// weights. Peak ≈ one layer.
    pub fn stream_layer(&mut self, l: usize) {
        let layer = build_layer_weights(&*self.backend, l, &self.config);
        rwkv7_layer_forward(
            &mut self.stream_x,
            &mut self.stream_v_first,
            &layer,
            &mut self.states[l],
            l,
            &self.config,
        );
    }

    /// Time-mix half of layer `l`: build ONLY the time-mix weights (the host paged
    /// them in), run time-mixing on `stream_x`, advance `states[l]`. Peak ≈ the
    /// time-mix matrices (r/k/v/o + low-rank), NOT a whole layer.
    pub fn stream_layer_timemix(&mut self, l: usize) {
        let layer = build_layer_weights_part(&*self.backend, l, &self.config, LayerPart::TimeMix);
        rwkv7_time_mix_forward(
            &mut self.stream_x,
            &mut self.stream_v_first,
            &layer,
            &mut self.states[l],
            l,
            &self.config,
        );
    }

    /// Channel-mix half of layer `l`: build ONLY the ffn weights, run channel-mixing
    /// on `stream_x`, advance `states[l]`. Peak ≈ the ffn matrices.
    pub fn stream_layer_channelmix(&mut self, l: usize) {
        let layer = build_layer_weights_part(&*self.backend, l, &self.config, LayerPart::ChannelMix);
        rwkv7_channel_mix_forward(&mut self.stream_x, &layer, &mut self.states[l], &self.config);
    }

    /// **Batched** time-mix half of layer `l`: build the time-mix weights ONCE (the host
    /// paged them in) and apply them to ALL `n` lanes' carried residuals `xs` + per-lane
    /// states via [`rwkv7_time_mix_forward_batch`] — one weight page+dequant serves the
    /// whole wave (the station-side width-axis amortization, the windmill's `~L×` lever).
    /// Lane state is EXTERNAL (the caller owns `xs`/`v_firsts`/`states`), so the station
    /// stays re-entrant. Bit-identical, per lane, to `n` [`stream_layer_timemix`] calls.
    pub fn stream_layer_timemix_batch(
        &self,
        l: usize,
        xs: &mut [Vec<f32>],
        v_firsts: &mut [Vec<f32>],
        states: &mut [RWKV7LayerState],
    ) {
        let layer = build_layer_weights_part(&*self.backend, l, &self.config, LayerPart::TimeMix);
        rwkv7_time_mix_forward_batch(xs, v_firsts, &layer, states, l, &self.config);
    }

    /// **Batched** channel-mix half of layer `l` (twin of [`stream_layer_channelmix`]).
    pub fn stream_layer_channelmix_batch(
        &self,
        l: usize,
        xs: &mut [Vec<f32>],
        states: &mut [RWKV7LayerState],
    ) {
        let layer = build_layer_weights_part(&*self.backend, l, &self.config, LayerPart::ChannelMix);
        rwkv7_channel_mix_forward_batch(xs, &layer, states, &self.config);
    }

    // ── Pinned-station I/O ────────────────────────────────────────────────────
    // A fleet station holds a CONTIGUOUS layer range's weights resident (warm) and
    // is STATELESS: the request payload carries the residual (`stream_x`), the
    // token-shared `v_first`, and the recurrent-state shards for the station's
    // layers. The station imports them, runs stream_layer_timemix/channelmix over
    // its range (weights already resident → zero R2 on the hot path), and exports
    // them back. Only ~residual + the range's small state cross the wire.
    pub fn set_stream_x(&mut self, x: Vec<f32>) { self.stream_x = x; }
    pub fn stream_x_ref(&self) -> &[f32] { &self.stream_x }
    pub fn set_stream_v_first(&mut self, v: Vec<f32>) { self.stream_v_first = v; }
    pub fn stream_v_first_ref(&self) -> &[f32] { &self.stream_v_first }
    pub fn layer_state_ref(&self, l: usize) -> &RWKV7LayerState { &self.states[l] }
    pub fn layer_state_mut(&mut self, l: usize) -> &mut RWKV7LayerState { &mut self.states[l] }

    /// Finish a token: final norm + lm_head over the carried residual → `logits`.
    pub fn stream_logits(&mut self, logits: &mut [f32]) {
        let normed_out = layer_norm(&self.stream_x, &self.output_norm_w, &self.output_norm_b);
        assert_eq!(logits.len(), self.config.vocab_size);
        let lm_w = self.resident_lm_w();
        let mut scratch: Vec<f32> = Vec::new();
        matvec_resident(logits, lm_w, &normed_out, &mut scratch);
    }

    /// The resident lm_head matrix (separate `output_weight`, else tied
    /// `token_embd`). Panics on a streaming pipeline — use stream_logits_shard.
    fn resident_lm_w(&self) -> &ResidentMat {
        self.lm_head
            .as_ref()
            .or(self.token_embd.as_ref())
            .expect("resident lm_head/token_embd (streaming pipe? use stream_logits_shard)")
    }

    /// The lm_head source tensor the host should page in shards (`output_weight`,
    /// else tied `token_embd_weight`).
    pub fn lm_src_name(&self) -> String {
        self.lm_src_name.clone()
    }

    /// Final-norm a carried residual — the shared front half of the vocab-sharded
    /// lm_head. `stream_logits_begin` is `stream_normed = final_norm(stream_x)`;
    /// the batched bindings cache one of these per selected lane, so both paths
    /// run the IDENTICAL norm.
    pub fn final_norm(&self, x: &[f32]) -> Vec<f32> {
        layer_norm(x, &self.output_norm_w, &self.output_norm_b)
    }

    /// Begin the streaming (vocab-sharded) lm_head: cache the final-norm output so
    /// each `stream_logits_shard` reuses it.
    pub fn stream_logits_begin(&mut self) {
        self.stream_normed = self.final_norm(&self.stream_x);
    }

    /// Argmax over lm_head rows [row_lo, row_hi): the host paged that shard as the
    /// tensor `lm_head_shard` ([rows, hidden] in source quant). Returns
    /// `[best_global_idx_as_f32, best_val]`; the host combines across shards.
    pub fn stream_logits_shard(&self, row_lo: u32, row_hi: u32) -> Vec<f32> {
        let lo = row_lo as usize;
        let rows = (row_hi - row_lo) as usize;
        let d = self.config.hidden_dim;
        let bytes = self
            .backend
            .fetch_tensor("lm_head_shard")
            .expect("stream_logits_shard: host must set 'lm_head_shard'");
        let shard = ResidentMat::from_parts(bytes, self.lm_qtype, rows, d);
        let mut logits = vec![0.0f32; rows];
        let mut scratch: Vec<f32> = Vec::new();
        matvec_resident(&mut logits, &shard, &self.stream_normed, &mut scratch);
        let mut best = 0usize;
        let mut bv = f32::NEG_INFINITY;
        for (i, &v) in logits.iter().enumerate() {
            if v > bv {
                bv = v;
                best = i;
            }
        }
        vec![(lo + best) as f32, bv]
    }

    /// **Batched** twin of [`stream_logits_shard`](Self::stream_logits_shard): argmax
    /// over lm_head rows [row_lo, row_hi) (host paged the shard as `lm_head_shard`)
    /// for EVERY lane's final-normed residual in `normed`, dequantizing each shard
    /// row ONCE and dotting it against all lanes (the bmatvec amortization —
    /// `Gnosis.WarpBatchAmortization.sharedCost`: one weight read serves the wave).
    /// Returns the solo `[best_global_idx_as_f32, best_val]` pair PER lane, flat in
    /// `normed` order: `[idx_0, val_0, idx_1, val_1, …]`; the host keeps each lane's
    /// running max across shards. Bit-identical, per lane, to a solo
    /// `stream_logits_begin` + `stream_logits_shard` over the same residual.
    pub fn stream_logits_shard_batch(
        &self,
        row_lo: u32,
        row_hi: u32,
        normed: &[Vec<f32>],
    ) -> Vec<f32> {
        let lo = row_lo as usize;
        let rows = (row_hi - row_lo) as usize;
        let d = self.config.hidden_dim;
        let bytes = self
            .backend
            .fetch_tensor("lm_head_shard")
            .expect("stream_logits_shard_batch: host must set 'lm_head_shard'");
        let shard = ResidentMat::from_parts(bytes, self.lm_qtype, rows, d);
        let n = normed.len();
        // Width-1 wave: the solo shard body on lane 0's residual — same matvec +
        // argmax as stream_logits_shard, no Vec-of-Vec logits, same [idx, val] frame.
        if n == 1 {
            let mut logits = vec![0.0f32; rows];
            let mut scratch: Vec<f32> = Vec::new();
            matvec_resident(&mut logits, &shard, &normed[0], &mut scratch);
            let mut best = 0usize;
            let mut bv = f32::NEG_INFINITY;
            for (i, &v) in logits.iter().enumerate() {
                if v > bv {
                    bv = v;
                    best = i;
                }
            }
            return vec![(lo + best) as f32, bv];
        }
        let mut logits: Vec<Vec<f32>> = vec![vec![0.0f32; rows]; n];
        let mut scratch: Vec<f32> = Vec::new();
        bmatvec(&mut logits, Some(&shard), normed, &mut scratch);
        let mut out = Vec::with_capacity(2 * n);
        for lane_logits in &logits {
            let mut best = 0usize;
            let mut bv = f32::NEG_INFINITY;
            for (i, &v) in lane_logits.iter().enumerate() {
                if v > bv {
                    bv = v;
                    best = i;
                }
            }
            out.push((lo + best) as f32);
            out.push(bv);
        }
        out
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Bit-exact resident-matvec tests (mirror STT's mat_vec_q8 proof)
// ─────────────────────────────────────────────────────────────────────────────
#[cfg(test)]
mod resident_matvec_tests {
    use super::*;

    fn owned(buf: Vec<u8>) -> OwnedBytes {
        OwnedBytes::Owned(Arc::new(buf))
    }

    /// Build a synthetic GGUF Q8_0 matrix (`rows`×`cols`, cols a multiple of 32)
    /// and the EXACT f32 values it dequantizes to. Each 34-byte block is
    /// `[f16 scale][32 i8]`; we pick the scale as a raw f16 bit pattern so the
    /// reference uses the identical `f16_to_f32(bits)` the kernel reads.
    fn make_q8_0(rows: usize, cols: usize) -> (Vec<u8>, Vec<f32>) {
        assert_eq!(cols % 32, 0);
        let bpr = cols / 32;
        let mut bytes = vec![0u8; rows * bpr * 34];
        let mut deq = vec![0.0f32; rows * cols];
        for r in 0..rows {
            for b in 0..bpr {
                let off = (r * bpr + b) * 34;
                // f16 scale bit pattern (small positive value), varies per block.
                let scale_bits: u16 = 0x2000u16.wrapping_add((r * 7 + b * 13) as u16 & 0x0fff);
                bytes[off] = (scale_bits & 0xff) as u8;
                bytes[off + 1] = (scale_bits >> 8) as u8;
                let scale = f16_to_f32(scale_bits);
                for j in 0..32 {
                    let q = (((r * 31 + b * 17 + j * 5) % 255) as i32 - 127) as i8;
                    bytes[off + 2 + j] = q as u8;
                    deq[r * cols + b * 32 + j] = q as f32 * scale;
                }
            }
        }
        (bytes, deq)
    }

    #[test]
    fn matvec_resident_q8_matches_bulk_dequant() {
        let (rows, cols) = (40usize, 64usize);
        let (bytes, deq) = make_q8_0(rows, cols);
        let x: Vec<f32> = (0..cols).map(|c| (c as f32 * 0.013 - 0.3).sin()).collect();

        let mat = ResidentMat {
            bytes: owned(bytes),
            qtype: QType::Q8_0,
            rows,
            cols,
        };
        let mut out_resident = vec![0.0f32; rows];
        let mut scratch = Vec::new();
        matvec_resident(&mut out_resident, &mat, &x, &mut scratch);

        // Reference: bulk-dequantized matrix, row-wise through the SAME dot.
        let mut out_bulk = vec![0.0f32; rows];
        for i in 0..rows {
            out_bulk[i] = seq_dot(&deq[i * cols..(i + 1) * cols], &x);
        }

        assert_eq!(
            out_resident, out_bulk,
            "Q8-resident matvec must be BIT-IDENTICAL to bulk-dequant + f32 matmul"
        );
    }

    #[test]
    fn matvec_resident_f16_matches_bulk_dequant() {
        let (rows, cols) = (33usize, 48usize);
        // F16 matrix: 2 bytes/elem, row-major; reference uses the same decode.
        let mut bytes = vec![0u8; rows * cols * 2];
        let mut deq = vec![0.0f32; rows * cols];
        for r in 0..rows {
            for c in 0..cols {
                let bits: u16 = 0x3000u16.wrapping_add((r * 11 + c * 3) as u16 & 0x0fff);
                let o = (r * cols + c) * 2;
                bytes[o] = (bits & 0xff) as u8;
                bytes[o + 1] = (bits >> 8) as u8;
                deq[r * cols + c] = f16_to_f32(bits);
            }
        }
        let x: Vec<f32> = (0..cols).map(|c| (c as f32 * 0.021).cos()).collect();
        let mat = ResidentMat {
            bytes: owned(bytes),
            qtype: QType::F16,
            rows,
            cols,
        };
        let mut out_resident = vec![0.0f32; rows];
        let mut scratch = Vec::new();
        matvec_resident(&mut out_resident, &mat, &x, &mut scratch);
        let mut out_bulk = vec![0.0f32; rows];
        for i in 0..rows {
            out_bulk[i] = seq_dot(&deq[i * cols..(i + 1) * cols], &x);
        }
        assert_eq!(
            out_resident, out_bulk,
            "F16-resident matvec must be BIT-IDENTICAL to bulk-dequant + f32 matmul"
        );
    }

    /// Micro parity gate for the multi-lane kernel contract: the batched matvec must be
    /// BIT-IDENTICAL, per lane, to `n` solo `matvec_resident` calls. On native this
    /// exercises the shared-dequant scalar path; on wasm the same contract is carried by
    /// `dot_q8_row_simd128_lanes` replaying the solo fused kernel's accumulation order
    /// per lane (identical op sequence ⇒ identical bits).
    #[test]
    fn matvec_resident_batch_q8_matches_per_lane_solo() {
        let (rows, cols) = (40usize, 96usize);
        let (bytes, _deq) = make_q8_0(rows, cols);
        let mat = ResidentMat {
            bytes: owned(bytes),
            qtype: QType::Q8_0,
            rows,
            cols,
        };
        let lanes = 5usize; // deliberately not a power of two
        let xs_own: Vec<Vec<f32>> = (0..lanes)
            .map(|k| {
                (0..cols)
                    .map(|c| ((c as f32 + k as f32 * 3.7) * 0.017 - 0.4).sin())
                    .collect()
            })
            .collect();

        // Solo reference: one matvec_resident per lane.
        let mut solo = vec![vec![0.0f32; rows]; lanes];
        let mut scratch = Vec::new();
        for k in 0..lanes {
            matvec_resident(&mut solo[k], &mat, &xs_own[k], &mut scratch);
        }

        // Batched: one shared-weight-read matvec across all lanes.
        let mut batched = vec![vec![0.0f32; rows]; lanes];
        let mut brefs: Vec<&mut [f32]> = batched.iter_mut().map(|v| v.as_mut_slice()).collect();
        let xrefs: Vec<&[f32]> = xs_own.iter().map(|v| v.as_slice()).collect();
        let mut bscratch = Vec::new();
        matvec_resident_batch(&mut brefs, &mat, &xrefs, &mut bscratch);

        assert_eq!(
            batched, solo,
            "batched Q8 matvec must be BIT-IDENTICAL per lane to solo matvec_resident"
        );
    }
}
